const loadImageWorkspaceValue = (key, fallback) => {
  try {
    const raw = localStorage.getItem(LS_IMAGE_WORKSPACE);
    if (!raw) return fallback;
    const parsed = JSON.parse(raw);
    return parsed?.[key] ?? fallback;
  } catch { return fallback; }
};

