  // Relationship-level deprecated
  "meetsInChapter", "meetsInDate",
  // Plot-level deprecated (date ranges replaced by 'date')
  "chapterDate", "chapterStartDate", "chapterEndDate",
  // Misc AI-hallucinated fields
