// Helper: extract plain text from HTML content
const _htmlToPlain = (html) => {
  if (!html) return "";
  // FIX 1.23: Convert <br> to newlines and <p> boundaries to double newlines before stripping
  return html.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>\s*<p[^>]*>/gi, '\n\n')
    .replace(/<[^>]*>/g, ' ').replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#\d+;/g, ' ').replace(/&[a-z]+;/gi, ' ')
    .replace(/\s+/g, ' ').trim();
};

// A12/A13/B6/C5: Truncate text at the nearest sentence or clause boundary
const _truncateAtBoundary = (text, maxLen) => {
  if (!text || text.length <= maxLen) return text;
  const sliced = text.slice(0, maxLen);
  // Try sentence boundary first
  const sentenceMatches = [...sliced.matchAll(/[.!?]["'»)]*\s/g)];
  if (sentenceMatches.length > 0) {
    const last = sentenceMatches[sentenceMatches.length - 1];
    return sliced.slice(0, last.index + last[0].length).trim();
  }
  // Try clause boundary (comma, semicolon, dash)
  const clauseMatches = [...sliced.matchAll(/[,;—–]\s/g)];
  if (clauseMatches.length > 0) {
    const last = clauseMatches[clauseMatches.length - 1];
    return sliced.slice(0, last.index + last[0].length).trim();
  }
  // Fallback: last space
  const spaceIdx = sliced.lastIndexOf(' ');
  return spaceIdx > 0 ? sliced.slice(0, spaceIdx) : sliced;
};

// Fix #28: Improved boundary slicing — finds the boundary closest to the cut point
const _sliceAtBoundary = (text, maxLen) => {
  if (text.length <= maxLen) return text;
  const sliced = text.slice(-maxLen);
  // Look for a sentence boundary within the first 15% of the sliced text (near the cut)
  const searchZone = sliced.slice(0, Math.max(80, Math.floor(maxLen * 0.15)));
  const lastBoundary = searchZone.search(/[.!?]["'»)]*\s(?=[A-Z])/);
  if (lastBoundary > 0) {
    const boundaryEnd = searchZone.indexOf(' ', lastBoundary + 1);
    if (boundaryEnd > 0) return sliced.slice(boundaryEnd + 1);
  }
  // Fallback: find first space
  const spaceIdx = sliced.indexOf(' ');
  return spaceIdx > 0 ? sliced.slice(spaceIdx + 1) : sliced;
};

// Fix #3: Slice from the head at a sentence boundary (for extracting chapter openings)
const _sliceHeadAtBoundary = (text, maxLen) => {
  if (text.length <= maxLen) return text;
  const sliced = text.slice(0, maxLen);
  // Find the last sentence boundary in the sliced text
  const matches = [...sliced.matchAll(/[.!?]["'»)]*\s/g)];
  if (matches.length > 0) {
    const lastMatch = matches[matches.length - 1];
    return sliced.slice(0, lastMatch.index + lastMatch[0].length - 1);
  }
  // Fallback: last space
  const spaceIdx = sliced.lastIndexOf(' ');
  return spaceIdx > 0 ? sliced.slice(0, spaceIdx) : sliced;
};

// Robust character detection — word-boundary, aliases, length-prioritized
// Common English words that are also frequently used as names — matching these case-insensitively
// caused massive false positives ("grace", "will", "rose", "dawn", "art"...). We only treat such a
// token as a character mention when it appears Capitalized in the prose (i.e. used as a proper noun).
const _COMMON_WORD_NAMES = new Set([
  "will","grace","rose","dawn","art","hope","faith","joy","mark","bill","jack","rich","mary",
  "summer","autumn","sky","river","brook","fern","ivy","holly","jasmine","crystal","amber","ruby",
  "pearl","violet","daisy","lily","iris","heather","june","may","jay","drew","reed","cliff","dale",
  "frank","earl","red","grey","gray","brown","stone","king","price","love","angel","melody","star",
]);

// Build the set of characters explicitly mentioned in `text`.
// Strategy (in priority order, designed to AVOID false positives):
//   1. Full name (case-insensitive) or any alias → unambiguous, always counts.
//   2. A single name-part (first OR last) → counts ONLY if that token is unique to one character
//      AND (the token is capitalized in the text OR it isn't a common English word).
const _detectMentionedCharacters = (text, characters) => {
  if (!text || !characters?.length) return new Set();
  const mentioned = new Set();

  const escape = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const testWord = (token, caseSensitive) => {
    if (!token || token.length < 2) return false;
    try {
      const re = new RegExp(`\\b${escape(token)}\\b`, caseSensitive ? "" : "i");
      return re.test(text);
    } catch { return false; }
  };

  // Count how many characters lay claim to each name-part token, so we can detect ambiguity
  // (e.g. two characters both named "John ...", or a surname shared by a family).
  const partOwners = new Map(); // token(lowercased) -> Set of character ids
  const claim = (tok, id) => {
    if (!tok) return;
    const k = tok.toLowerCase();
    if (!partOwners.has(k)) partOwners.set(k, new Set());
    partOwners.get(k).add(id);
  };
  for (const c of characters) {
    if (!c.name) continue;
    const parts = c.name.trim().split(/\s+/);
    if (parts[0]) claim(parts[0], c.id);
    if (parts.length > 1) claim(parts[parts.length - 1], c.id);
  }

  for (const c of characters) {
    if (!c.name) continue;

    // 1) Full name (≥ 2 chars) — case-insensitive, unambiguous.
    const full = c.name.trim();
    if (full.length >= 2 && testWord(full, false)) { mentioned.add(c.id); continue; }

    // Aliases — treat like full names (the writer chose them deliberately).
    let aliasHit = false;
    if (c.aliases) {
      const aliasList = (Array.isArray(c.aliases) ? c.aliases : String(c.aliases).split(","))
        .map(a => String(a).trim()).filter(a => a.length >= 2);
      for (const a of aliasList) {
        // Short aliases (≤3) require capitalization to avoid common-word collisions.
        const cs = a.length <= 3 || _COMMON_WORD_NAMES.has(a.toLowerCase());
        if (testWord(a, cs)) { aliasHit = true; break; }
      }
    }
    if (aliasHit) { mentioned.add(c.id); continue; }

    // 2) Single name-part fallback — only if unambiguous (owned by exactly one character).
    const parts = full.split(/\s+/);
    const candidates = [];
    if (parts[0]) candidates.push(parts[0]);
    if (parts.length > 1) candidates.push(parts[parts.length - 1]);
    let hit = false;
    for (const tok of candidates) {
      if (tok.length < 2) continue;
      const owners = partOwners.get(tok.toLowerCase());
      if (!owners || owners.size !== 1) continue; // ambiguous → skip (prevents "Smith" cross-matches)
      // Capitalized in prose, OR not a common word and length ≥ 4.
      const needsCap = tok.length <= 3 || _COMMON_WORD_NAMES.has(tok.toLowerCase());
      if (testWord(tok, needsCap)) { hit = true; break; }
    }
    if (hit) mentioned.add(c.id);
  }
  return mentioned;
};

// Classify HOW each detected character appears: actually present in the scene, or merely
// referenced/talked-about while absent. The old code treated any mention as "in scene", so a
// character that another character merely talks about (e.g. "I haven't seen Elena in years")
// was wrongly described to the writing AI as present. This separates the two.
// Returns { present: Set<id>, referenced: Set<id> }.
const _classifyCharacterPresence = (text, characters, detectedIds, opts = {}) => {
  const present = new Set();
  const referenced = new Set();
  if (!detectedIds || detectedIds.size === 0) return { present, referenced };
  // Characters the author explicitly tagged for this scene (plot `characters`, scene notes
  // mentions, POV) are ALWAYS present regardless of prose phrasing.
  const forcedPresent = opts.forcedPresent instanceof Set ? opts.forcedPresent : new Set();

  // Absence/reference cue words near a name strongly imply the character is NOT in the scene.
  const ABSENCE_CUES = /\b(ha(?:d|s|ve)(?:n't| not)? (?:seen|met|heard from|spoken to|been with)|never (?:seen|met)|hasn't seen|haven't seen|used to|years? ago|long ago|in years|since (?:then|the)|missed|missing|gone|absent|away|left for|departed|thinking (?:of|about)|remembered|recalled|reminded (?:of|her of|him of)|dreamed (?:of|about)|wished|if only|where (?:was|is|were|had)|letter from|message from|note from|news of|word from|spoke of|speaks of|talked about|talking about|told (?:her|him|them) about|mentioned|story about|stories of|legend of|memory of|memories of|in memoriam|the late|deceased|buried|grave of|funeral|ghost of|portrait of|photograph of|picture of)\b/i;
  // Presence cues: the name directly drives an action or speech, or possesses a body part / nearby object.
  const buildPresenceRe = (nm) => {
    const n = nm.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    return new RegExp(
      `\\b${n}\\b\\s+(said|asked|replied|whispered|shouted|muttered|nodded|shrugged|smiled|laughed|frowned|turned|walked|stepped|moved|reached|grabbed|looked|glanced|stared|stood|sat|leaned|crossed|entered|paused|sighed|gasped|breathed|gestured|pointed|raised|lowered|opened|closed|drew|pulled|pushed|ran|stopped|spoke|answered|called|cried|screamed|nodded|stiffened|flinched)\\b` +
      `|\\b${n}'s\\s+(hand|hands|eyes|face|voice|fingers|arm|arms|chest|breath|gaze|lips|mouth|head|shoulder|shoulders|heart)\\b` +
      `|(?:said|asked|told|whispered|shouted|replied|called|warned|reminded|snapped)\\s+${n}\\b` +
      `|\\b(?:beside|next to|behind|in front of|across from|facing|near|toward|towards|at)\\s+${n}\\b`,
      "i");
  };

  for (const c of characters) {
    if (!detectedIds.has(c.id)) continue;
    if (forcedPresent.has(c.id)) { present.add(c.id); continue; }
    if (!c.name) { referenced.add(c.id); continue; }

    // Build the set of name tokens to scan for (full name + first name).
    const names = [c.name.trim()];
    const first = c.name.trim().split(/\s+/)[0];
    if (first && first !== c.name.trim()) names.push(first);
    if (c.aliases) {
      (Array.isArray(c.aliases) ? c.aliases : String(c.aliases).split(",")).forEach(a => { const t = String(a).trim(); if (t.length >= 2) names.push(t); });
    }

    let sawPresence = false;
    let sawAbsence = false;
    for (const nm of names) {
      try {
        if (buildPresenceRe(nm).test(text)) { sawPresence = true; }
      } catch {}
      // Check absence cue within ~40 chars of the name occurrence.
      try {
        const re = new RegExp(`(.{0,40}\\b${nm.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b.{0,40})`, "gi");
        let m;
        while ((m = re.exec(text)) !== null) {
          if (ABSENCE_CUES.test(m[1])) { sawAbsence = true; break; }
          if (re.lastIndex === m.index) re.lastIndex++;
        }
      } catch {}
      if (sawPresence) break;
    }

    if (sawPresence) present.add(c.id);
    else if (sawAbsence && !opts.relaxAbsence) referenced.add(c.id);
    else present.add(c.id); // ambiguous default: treat as present (conservative — old behavior)
  }
  return { present, referenced };
};

// FIX: Completely rewritten world detection — multi-strategy, includes description scanning
const _detectRelevantWorld = (text, worldEntries) => {
  if (!text || !worldEntries?.length) return new Set();
  const relevant = new Set();
  const lowerText = text.toLowerCase();
  const skipWords = new Set(["the","a","an","of","in","on","at","to","for","and","or","by","with","from","is","it","be","as","was","are","this","that","has","had","not","but","its"]);

  for (const w of worldEntries) {
    if (!w.name) continue;
    let matched = false;

    // Strategy 1: Full name match (case-insensitive, word-boundary for short names)
    const fullName = w.name.trim().toLowerCase();
    if (fullName.length > 0) {
      if (fullName.length <= 5) {
        const regex = new RegExp(`\\b${fullName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'i');
        if (regex.test(text)) matched = true;
      } else {
        if (lowerText.includes(fullName)) matched = true;
      }
    }

    // Strategy 2: Multi-word name — match if ALL significant words appear (not just any one)
    if (!matched) {
      const nameWords = w.name.trim().split(/\s+/).map(w => w.toLowerCase()).filter(w => w.length >= 3 && !skipWords.has(w));
      if (nameWords.length >= 2) {
        const allPresent = nameWords.every(word => {
          const regex = new RegExp(`\\b${word.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'i');
          return regex.test(text);
        });
        if (allPresent) matched = true;
      } else if (nameWords.length === 1 && nameWords[0].length >= 5) {
        // Single significant word from name — only match if it's long enough to be unique
        if (lowerText.includes(nameWords[0])) matched = true;
      }
    }

    // Strategy 3: Keywords — each keyword is checked individually (any match = relevant)
    if (!matched && w.keywords) {
      const kwList = Array.isArray(w.keywords) ? w.keywords : String(w.keywords).split(",");
      for (const rawKw of kwList) {
        const kw = String(rawKw).trim().toLowerCase();
        if (kw.length < 2) continue;
        if (kw.length <= 4) {
		  const escaped = kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
		  if (escaped && escaped.length > 0) {
		    try {
			  const regex = new RegExp(`\\b${escaped}\\b`, 'i');
			  if (regex.test(text)) { matched = true; break; }
			} catch(e) { /* skip bad regex */ }
		  }
	} else {
	  if (lowerText.includes(kw)) { matched = true; break; }
	}
	  }
	}
    // Strategy 4: Description-based detection — only as a LAST resort, and deliberately strict.
    // The old version matched on any 2 words of 6+ chars from the description, which pulled in
    // unrelated entries that merely shared generic words ("ancient", "wooden", "morning"). We now
    // require several long, distinctive words to co-occur before calling an entry relevant.
    if (!matched && w.description) {
      const descWords = w.description.toLowerCase().split(/[\s,.;:!?()[\]{}"']+/)
        .filter(dw => dw.length >= 8 && !skipWords.has(dw));
      const uniqueDescWords = [...new Set(descWords)].slice(0, 12);
      const descMatches = uniqueDescWords.filter(dw => lowerText.includes(dw)).length;
      if (descMatches >= 3) matched = true;
    }

    if (matched) relevant.add(w.id);
  }
  return relevant;
};

// FIX: Resolve character ID to name — used by relationships and plot outlines that store IDs
const _resolveCharName = (charId, characters) => {
  if (!charId || !characters?.length) return charId || "";
  const c = characters.find(ch => ch.id === charId);
  return c ? c.name : charId; // Fallback to the raw value if not found (legacy name-based data)
};

// FIX: Resolve character name to ID — used for migration and matching
const _resolveCharId = (nameOrId, characters) => {
  if (!nameOrId || !characters?.length) return nameOrId || "";
  // Check if it's already an ID
  const byId = characters.find(c => c.id === nameOrId);
  if (byId) return nameOrId;
  // Try matching by name (case-insensitive)
  const byName = characters.find(c => c.name && c.name.toLowerCase() === nameOrId.toLowerCase());
  return byName ? byName.id : nameOrId; // Return original if no match
};

// Strip a POV-style prefix ("Third person limited - Elena", "First person — Marcus", etc.)
// from a POV string, leaving just the character name (if any).
const POV_PREFIX_RE = /^(Third person limited|Third person deep|Third person omniscient|First person|First person present tense|Second person|Multiple POV[^-—:]*|Dual POV[^-—:]*)\s*[-—:]\s*/i;
const _stripPovPrefix = (povString) => (povString || "").replace(POV_PREFIX_RE, "").trim();

// ═══ CANONICAL FIELD SCHEMAS — single source of truth ═══
// Every place that lists "what fields exist" (AI fill, bulk-gen, system prompts, empty-field
// detection) must reference these so the lists can never drift apart. Drift was causing the
// AI to never be asked for — or to silently drop — fields that the editor actually renders.
const CHARACTER_TEXT_FIELDS = [
  "gender","age","pronouns","orientation","aliases","occupation","height","build","tags",
  "appearance","personality","backstory","desires","shortTermGoals","longTermGoals",
  "speechPattern","voiceSamples","habits","fears","flaws","strengths","skills",
  "internalConflict","externalConflict","signatureItems","secrets","hiddenSecrets",
  "allegiances","arc","canonNotes",
];
// World fields the editor renders, keyed by category. "description"/"keywords" + the two common
// fields (history, culturalNorms) apply to every category; category-specific fields follow.
const WORLD_COMMON_FIELDS = ["description","keywords","history","culturalNorms"];
const WORLD_UI_CATEGORIES = ["Location","Organization","Rule / Law","Culture","Magic System","Technology","History","Religion","Flora / Fauna","Language","Other"];
const WORLD_CATEGORY_FIELDS = {
  "Location": ["atmosphere","sensoryDetails","subLocations","dangers","rules","population","resources"],
  "Rule / Law": ["enforcement","scope","loopholes","publicOpinion","enactedBy"],
  "Culture": ["values","customs","socialHierarchy","taboos","artForms","dialect","population"],
  "Organization": ["orgPurpose"],
  "Magic System": ["magicSource","magicRules","magicCost","magicRarity","magicTypes","magicPerception","magicPractitioners"],
  "Technology": ["techFunction","techMechanism","techAvailability","techLimitations","techImpact","techCreator"],
  "History": ["historyDate","historyFigures","historyCauses","historyConsequences","historyLegacy","historyDisputed"],
  "Flora / Fauna": ["habitat","floraAppearance","behavior","floraUses","floraRarity","floraCultural"],
  "Language": ["langSpeakers","langWriting","langPhrases","langGrammar","langRelated","langStatus"],
  "Religion": ["deities","coreBeliefs","rituals","sacredPlaces","clergy","heresies","followers"],
  "Other": ["additionalNotes"],
};
// Full fillable text-field list for a given world category (common + category-specific).
const worldFieldsForCategory = (cat) => [
  ...WORLD_COMMON_FIELDS.filter(f => f !== "history" && f !== "culturalNorms"),
  ...(WORLD_CATEGORY_FIELDS[cat] || WORLD_CATEGORY_FIELDS["Location"]),
  "history","culturalNorms",
];
// Every world text field across all categories (used by bulk-gen which doesn't know category yet).
const ALL_WORLD_TEXT_FIELDS = [...new Set([
  "description","keywords","atmosphere","sensoryDetails","subLocations","dangers","rules",
  "population","resources","orgPurpose","history","culturalNorms",
  ...Object.values(WORLD_CATEGORY_FIELDS).flat(),
])];
const RELATIONSHIP_TEXT_FIELDS = [
  "dynamic","chemistry","conflictSource","sharedSecrets","keyScenes","terms","taboos",
  "progression","char1Perspective","char2Perspective","evolutionTimeline","notes",
];

// ─── CROSS-REFERENCE ENGINE: derives all interconnected data from project ───
const _deriveCrossRefs = (project, charId, opts = {}) => {
  if (!project) return {};
  const chars = project.characters || [];
  const worlds = project.worldBuilding || [];
  const rels = project.relationships || [];
  const plots = project.plotOutline || [];
  const result = {};

  // ─── LOCATION-LEVEL cross-refs (when opts.worldId is set) ───
  if (opts.worldId) {
    const w = worlds.find(ww => ww.id === opts.worldId);
    if (w) {
      const fc = Array.isArray(w.frequentCharacters) ? w.frequentCharacters : [];
      result.locChars = fc.map(cid => chars.find(c => c.id === cid)).filter(Boolean);
      result.locPlotChapters = plots.filter(pl => Array.isArray(pl.locations) && pl.locations.includes(opts.worldId));
      result.locRelationships = rels.filter(r => fc.includes(r.char1) && fc.includes(r.char2));
      result.locConnectedEntries = (Array.isArray(w.connectedTo) ? w.connectedTo : []).map(cid => worlds.find(ww => ww.id === cid)).filter(Boolean);
      // Orgs that control/operate from this location
      result.locOrgs = worlds.filter(ww => ww.category === "Organization" && Array.isArray(ww.connectedTo) && ww.connectedTo.includes(opts.worldId));
      // Chars with secrets related to this location
      result.locSecretChars = chars.filter(c => fc.includes(c.id) && (c.secrets || c.hiddenSecrets));
      // Tension map at this location
      result.locTensions = result.locRelationships.filter(r => r.tension && r.tension !== "none").map(r => {
        const c1 = chars.find(c => c.id === r.char1); const c2 = chars.find(c => c.id === r.char2);
        return { c1: c1?.name, c2: c2?.name, tension: r.tension, category: r.category, dynamic: r.dynamic };
      });
      // Cultural norms that affect characters here
      result.locNorms = w.culturalNorms || "";
      result.locHistory = w.history || "";
      result.locResources = w.resources || "";
      // Category-specific cross-ref data
      if (w.category === "Location" || !w.category) {
        result.locAtmosphere = w.atmosphere || "";
        result.locDangers = w.dangers || "";
        result.locRules = w.rules || "";
      }
      if (w.category === "Magic System") {
        result.locMagicRules = w.magicRules || "";
        result.locMagicSource = w.magicSource || "";
      }
      if (w.category === "Religion") {
        result.locReligionBeliefs = w.coreBeliefs || "";
        result.locReligionRituals = w.rituals || "";
      }
      // Sub-locations
      result.locSubLocations = w.subLocations || "";
      // Parent location
      result.locParent = w.parentLocation ? worlds.find(ww => ww.id === w.parentLocation) : null;
      // Child locations
      result.locChildren = worlds.filter(ww => ww.parentLocation === opts.worldId && ww.name);
    }
  }

  // ─── RELATIONSHIP-LEVEL cross-refs (when opts.relId is set) ───
  if (opts.relId) {
    const r = rels.find(rr => rr.id === opts.relId);
    if (r) {
      const c1 = chars.find(c => c.id === r.char1);
      const c2 = chars.find(c => c.id === r.char2);
      result.relChar1 = c1; result.relChar2 = c2;
      // Shared locations
      result.relSharedLocs = worlds.filter(w => (w.category === "Location" || !w.category) && Array.isArray(w.frequentCharacters) && w.frequentCharacters.includes(r.char1) && w.frequentCharacters.includes(r.char2) && w.name);
      // Shared orgs
      result.relSharedOrgs = worlds.filter(w => {
        if (w.category !== "Organization") return false;
        const c1In = (Array.isArray(w.orgHierarchy) && w.orgHierarchy.some(p => p.charId === r.char1)) || (Array.isArray(w.orgMembers) && w.orgMembers.includes(r.char1));
        const c2In = (Array.isArray(w.orgHierarchy) && w.orgHierarchy.some(p => p.charId === r.char2)) || (Array.isArray(w.orgMembers) && w.orgMembers.includes(r.char2));
        return c1In && c2In && w.name;
      });
      // Shared plot chapters
      result.relSharedChapters = plots.filter(pl => Array.isArray(pl.characters) && pl.characters.includes(r.char1) && pl.characters.includes(r.char2));
      // Org hierarchy relationship (does one report to the other?)
      result.relOrgHierarchy = [];
      worlds.forEach(w => {
        if (w.category !== "Organization" || !Array.isArray(w.orgHierarchy)) return;
        const p1 = w.orgHierarchy.find(p => p.charId === r.char1);
        const p2 = w.orgHierarchy.find(p => p.charId === r.char2);
        if (p1 && p2) {
          if (p1.parentId && w.orgHierarchy.find(p => p.id === p1.parentId)?.charId === r.char2) result.relOrgHierarchy.push({ org: w.name, superior: c2?.name, subordinate: c1?.name });
          if (p2.parentId && w.orgHierarchy.find(p => p.id === p2.parentId)?.charId === r.char1) result.relOrgHierarchy.push({ org: w.name, superior: c1?.name, subordinate: c2?.name });
        }
      });
      // Mutual friends/enemies (other characters connected to both)
      result.relMutualConnections = [];
      chars.forEach(c => {
        if (c.id === r.char1 || c.id === r.char2) return;
        const hasRelWith1 = rels.some(rr => (rr.char1 === r.char1 && rr.char2 === c.id) || (rr.char2 === r.char1 && rr.char1 === c.id));
        const hasRelWith2 = rels.some(rr => (rr.char1 === r.char2 && rr.char2 === c.id) || (rr.char2 === r.char2 && rr.char1 === c.id));
        if (hasRelWith1 && hasRelWith2) result.relMutualConnections.push(c.name);
      });
      // Personality compatibility hints
      result.relPersonalityClash = c1?.personality && c2?.personality ? { p1: c1.personality.split(/[.,;]/)[0]?.trim(), p2: c2.personality.split(/[.,;]/)[0]?.trim() } : null;
      // Fear exploitation potential
      result.relFearOverlap = [];
      if (c1?.fears && c2?.personality) result.relFearOverlap.push({ fearer: c1.name, fear: c1.fears.split(/[.,;]/)[0]?.trim() });
      if (c2?.fears && c1?.personality) result.relFearOverlap.push({ fearer: c2.name, fear: c2.fears.split(/[.,;]/)[0]?.trim() });
    }
  }

  // ─── PLOT-LEVEL cross-refs (when opts.plotId is set) ───
  if (opts.plotId) {
    const pl = plots.find(pp => pp.id === opts.plotId);
    if (pl) {
      const selChars = Array.isArray(pl.characters) ? pl.characters : [];
      const selLocs = Array.isArray(pl.locations) ? pl.locations : [];
      // Location details
      result.plotLocDetails = selLocs.map(lid => worlds.find(w => w.id === lid)).filter(Boolean).map(loc => ({
        name: loc.name, atmosphere: loc.atmosphere, dangers: loc.dangers, rules: loc.rules, sensory: loc.sensoryDetails,
        subLocations: loc.subLocations, population: loc.population,
        charsHere: (loc.frequentCharacters || []).map(cid => chars.find(c => c.id === cid)?.name).filter(Boolean),
        charsNotInScene: (loc.frequentCharacters || []).filter(cid => !selChars.includes(cid)).map(cid => chars.find(c => c.id === cid)?.name).filter(Boolean),
      }));
      // Relationship dynamics between selected characters
      result.plotRelDynamics = rels.filter(r => selChars.includes(r.char1) && selChars.includes(r.char2)).map(r => ({
        c1: chars.find(c => c.id === r.char1)?.name, c2: chars.find(c => c.id === r.char2)?.name,
        status: r.status, tension: r.tension, category: r.category, dynamic: r.dynamic,
        terms: r.terms, powerDynamic: r.powerDynamic, trustLevel: r.trustLevel,
        isPublic: r.isPublic, sharedSecrets: r.sharedSecrets, taboos: r.taboos,
      }));
      // Dead characters in scene
      result.plotDeadChars = selChars.map(cid => chars.find(c => c.id === cid)).filter(c => c?.status === "dead");
      // Absent characters in scene
      result.plotAbsentChars = selChars.map(cid => chars.find(c => c.id === cid)).filter(c => c?.status === "absent");
      // Org dynamics in scene (characters from same org, hierarchy)
      result.plotOrgContext = [];
      worlds.forEach(w => {
        if (w.category !== "Organization" || !Array.isArray(w.orgHierarchy)) return;
        const inScene = w.orgHierarchy.filter(p => p.charId && selChars.includes(p.charId));
        if (inScene.length >= 2) {
          result.plotOrgContext.push({ org: w.name, members: inScene.map(p => ({ name: chars.find(c => c.id === p.charId)?.name, title: p.name })) });
        }
      });
      // POV character details
      if (pl.povCharacterId) {
        const povChar = chars.find(c => c.id === pl.povCharacterId);
        result.plotPovChar = povChar;
        result.plotPovCrossRef = _deriveCrossRefs(project, pl.povCharacterId);
      }
      // Previous chapter summary continuity
      const prevChapter = (pl.chapter || 1) - 1;
      const prevPlot = plots.find(pp => (pp.chapter || 0) === prevChapter);
      result.plotPrevChapter = prevPlot ? { title: prevPlot.title, summary: prevPlot.summary } : null;
      // Next chapter preview
      const nextChapter = (pl.chapter || 1) + 1;
      const nextPlot = plots.find(pp => (pp.chapter || 0) === nextChapter);
      result.plotNextChapter = nextPlot ? { title: nextPlot.title } : null;
    }
  }

  // ─── CHARACTER-LEVEL cross-refs ───
  if (charId) {
    result.charLocations = worlds.filter(w => (w.category === "Location" || !w.category) && Array.isArray(w.frequentCharacters) && w.frequentCharacters.includes(charId) && w.name);
    result.charOrgPositions = [];
    worlds.forEach(w => {
      if (w.category !== "Organization" || !Array.isArray(w.orgHierarchy)) return;
      w.orgHierarchy.forEach(pos => {
        if (pos.charId === charId) {
          const superior = pos.parentId ? w.orgHierarchy.find(p => p.id === pos.parentId) : null;
          const superiorChar = superior?.charId ? chars.find(c => c.id === superior.charId) : null;
          const subordinates = w.orgHierarchy.filter(p => p.parentId === pos.id && p.charId).map(p => {
            const sub = chars.find(c => c.id === p.charId);
            return sub ? { name: sub.name, title: p.name } : null;
          }).filter(Boolean);
          const peers = w.orgHierarchy.filter(p => p.parentId === pos.parentId && p.charId && p.charId !== charId).map(p => {
            const peer = chars.find(c => c.id === p.charId);
            return peer ? { name: peer.name, title: p.name } : null;
          }).filter(Boolean);
          result.charOrgPositions.push({ orgName: w.name, orgId: w.id, position: pos.name, role: pos.role, reportsTo: superiorChar?.name, reportsToTitle: superior?.name, subordinates, peers, orgPurpose: w.orgPurpose });
        }
      });
    });
    result.charOrgMemberships = worlds.filter(w => w.category === "Organization" && Array.isArray(w.orgMembers) && w.orgMembers.includes(charId) && w.name).map(w => w.name);
    result.charRelationships = rels.filter(r => r.char1 === charId || r.char2 === charId).map(r => {
      const otherId = r.char1 === charId ? r.char2 : r.char1;
      const other = chars.find(c => c.id === otherId);
      return { ...r, otherName: other?.name || "?", otherImage: other?.image, otherRole: other?.role, otherStatus: other?.status, otherPersonality: other?.personality?.split(/[.,;]/)[0]?.trim(), otherOrientation: other?.orientation };
    });
    result.charPlotAppearances = plots.filter(pl => Array.isArray(pl.characters) && pl.characters.includes(charId)).sort((a, b) => (a.chapter || 0) - (b.chapter || 0));
    result.derivedOccupation = result.charOrgPositions.map(o => `${o.position} (${o.orgName})`).join(", ");
    const allOrgNames = [...new Set([...result.charOrgPositions.map(o => o.orgName), ...result.charOrgMemberships])];
    result.derivedAllegiances = allOrgNames.join(", ");
    result.addressTerms = result.charRelationships.filter(r => r.terms).map(r => ({ name: r.otherName, terms: r.terms }));
    result.sharedSecrets = result.charRelationships.filter(r => r.sharedSecrets).map(r => ({ name: r.otherName, secret: r.sharedSecrets }));
    result.conflictSources = result.charRelationships.filter(r => r.conflictSource).map(r => ({ name: r.otherName, conflict: r.conflictSource }));
    result.powerDynamics = result.charRelationships.filter(r => r.powerDynamic && r.powerDynamic !== "equal").map(r => ({ name: r.otherName, dynamic: r.powerDynamic === "char1-dominant" ? (r.char1 === charId ? "dominant" : "submissive") : r.powerDynamic === "char2-dominant" ? (r.char2 === charId ? "dominant" : "submissive") : r.powerDynamic }));
    result.firstPlotChapter = result.charPlotAppearances.length > 0 ? result.charPlotAppearances[0].chapter : null;
    result.locationDangers = result.charLocations.filter(l => l.dangers).map(l => ({ name: l.name, dangers: l.dangers }));
    result.locationRules = result.charLocations.filter(l => l.rules).map(l => ({ name: l.name, rules: l.rules }));
    result.locationAtmospheres = result.charLocations.filter(l => l.atmosphere).map(l => ({ name: l.name, atmosphere: l.atmosphere }));
    result.locationSensory = result.charLocations.filter(l => l.sensoryDetails).map(l => ({ name: l.name, sensory: l.sensoryDetails }));
    result.coLocatedChars = [];
    result.charLocations.forEach(loc => {
      (loc.frequentCharacters || []).forEach(cid => {
        if (cid !== charId && !result.coLocatedChars.find(c => c.id === cid)) {
          const ch = chars.find(c => c.id === cid);
          if (ch) result.coLocatedChars.push({ id: cid, name: ch.name, role: ch.role, location: loc.name });
        }
      });
    });
    // Character → enemies (hostile relationships)
    result.enemies = result.charRelationships.filter(r => r.status === "enemies" || r.category === "rivalry" || r.tensionType === "hostile");
    // Character → allies (high trust relationships)
    result.allies = result.charRelationships.filter(r => (r.trustLevel === "high" || r.trustLevel === "absolute") && r.status !== "enemies");
    // Character → romantic interests
    result.romanticInterests = result.charRelationships.filter(r => r.category === "romantic" && r.status !== "strangers");
    // Character → secret relationships
    result.secretRelationships = result.charRelationships.filter(r => r.isPublic === false);
    // Character → taboos from relationships
    result.relTaboos = result.charRelationships.filter(r => r.taboos).map(r => ({ name: r.otherName, taboos: r.taboos }));
    // Character → chemistry descriptions
    result.relChemistry = result.charRelationships.filter(r => r.chemistry).map(r => ({ name: r.otherName, chemistry: r.chemistry }));
    // Character → evolution timelines
    result.relTimelines = result.charRelationships.filter(r => r.evolutionTimeline).map(r => ({ name: r.otherName, timeline: r.evolutionTimeline }));
    // Character → key scenes from relationships
    result.relKeyScenes = result.charRelationships.filter(r => r.keyScenes).map(r => ({ name: r.otherName, scenes: r.keyScenes }));
    // Character → POV chapters (where they're the viewpoint character)
    result.povChapters = plots.filter(pl => pl.povCharacterId === charId);
    // Character → connected world entries (via location connections)
    result.connectedWorldEntries = [];
    result.charLocations.forEach(loc => {
      (Array.isArray(loc.connectedTo) ? loc.connectedTo : []).forEach(cid => {
        const connected = worlds.find(w => w.id === cid);
        if (connected && !result.connectedWorldEntries.find(e => e.id === cid)) result.connectedWorldEntries.push(connected);
      });
    });
    // Character → peers in same org
    result.orgPeers = result.charOrgPositions.flatMap(o => o.peers || []);
    // Character → org purposes they serve
    result.orgPurposes = result.charOrgPositions.filter(o => o.orgPurpose).map(o => ({ org: o.orgName, purpose: o.orgPurpose }));
  }

  return result;
};

// Build a compact cross-ref context string for AI consumption
const _buildCrossRefContext = (project, charId) => {
  const cr = _deriveCrossRefs(project, charId);
  const lines = [];
  if (cr.derivedOccupation) lines.push(`Org position: ${cr.derivedOccupation}`);
  if (cr.derivedAllegiances) lines.push(`Allegiances (from orgs): ${cr.derivedAllegiances}`);
  if (cr.charLocations?.length) lines.push(`Frequents: ${cr.charLocations.map(l => `${l.name}${l.atmosphere ? ` (${l.atmosphere})` : ""}`).join(", ")}`);
  if (cr.addressTerms?.length) lines.push(`Address terms: ${cr.addressTerms.map(t => `${t.name}: "${t.terms}"`).join("; ")}`);
  if (cr.sharedSecrets?.length) lines.push(`Shared secrets: ${cr.sharedSecrets.map(s => `with ${s.name}: ${s.secret}`).join("; ")}`);
  if (cr.conflictSources?.length) lines.push(`Active conflicts: ${cr.conflictSources.map(c => `with ${c.name}: ${c.conflict}`).join("; ")}`);
  if (cr.charOrgPositions?.length) {
    cr.charOrgPositions.forEach(o => {
      let line = `Org role: ${o.position} in ${o.orgName}`;
      if (o.reportsTo) line += ` (reports to ${o.reportsTo}, ${o.reportsToTitle})`;
      if (o.subordinates?.length) line += ` (manages: ${o.subordinates.map(s => `${s.name} as ${s.title}`).join(", ")})`;
      if (o.peers?.length) line += ` (peers: ${o.peers.map(p => p.name).join(", ")})`;
      if (o.orgPurpose) line += ` — mission: ${_truncateAtBoundary(o.orgPurpose, 100)}`;
      lines.push(line);
    });
  }
  if (cr.coLocatedChars?.length) lines.push(`Co-located with: ${cr.coLocatedChars.map(c => `${c.name} (${c.role}) at ${c.location}`).join("; ")}`);
  if (cr.locationDangers?.length) lines.push(`Location dangers: ${cr.locationDangers.map(d => `${d.name}: ${d.dangers}`).join("; ")}`);
  if (cr.locationRules?.length) lines.push(`Location rules: ${cr.locationRules.map(r => `${r.name}: ${r.rules}`).join("; ")}`);
  if (cr.locationAtmospheres?.length) lines.push(`Location vibes: ${cr.locationAtmospheres.map(a => `${a.name}: ${a.atmosphere}`).join("; ")}`);
  if (cr.locationSensory?.length) lines.push(`Location sensory: ${cr.locationSensory.map(s => `${s.name}: ${s.sensory}`).join("; ")}`);
  if (cr.charRelationships?.length > 0) {
    const relSummary = cr.charRelationships.slice(0, 8).map(r => {
      let desc = `${r.otherName} (${r.category || "other"}, ${r.status || "?"})`;
      if (r.tension && r.tension !== "none") desc += ` [${r.tension} tension]`;
      if (r.trustLevel) desc += ` [trust: ${r.trustLevel}]`;
      return desc;
    });
    lines.push(`Relationships: ${relSummary.join("; ")}`);
  }
  if (cr.enemies?.length) lines.push(`Enemies/rivals: ${cr.enemies.map(e => e.otherName).join(", ")}`);
  if (cr.allies?.length) lines.push(`Trusted allies: ${cr.allies.map(a => `${a.otherName} (trust: ${a.trustLevel})`).join(", ")}`);
  if (cr.romanticInterests?.length) lines.push(`Romantic: ${cr.romanticInterests.map(r => `${r.otherName} (${r.status}, ${r.tension} tension)`).join(", ")}`);
  if (cr.secretRelationships?.length) lines.push(`Secret relationships: ${cr.secretRelationships.map(r => `${r.otherName} (${r.category})`).join(", ")}`);
  if (cr.relTaboos?.length) lines.push(`Relationship taboos: ${cr.relTaboos.map(t => `with ${t.name}: ${t.taboos}`).join("; ")}`);
  if (cr.relChemistry?.length) lines.push(`Chemistry: ${cr.relChemistry.map(c => `with ${c.name}: ${c.chemistry}`).join("; ")}`);
  if (cr.powerDynamics?.length) lines.push(`Power dynamics: ${cr.powerDynamics.map(p => `${p.dynamic} over/under ${p.name}`).join("; ")}`);
  if (cr.povChapters?.length) lines.push(`POV in chapters: ${cr.povChapters.map(p => `Ch${p.chapter || "?"}`).join(", ")}`);
  if (cr.charPlotAppearances?.length) lines.push(`Appears in chapters: ${cr.charPlotAppearances.map(p => `Ch${p.chapter || "?"}`).join(", ")}`);
  if (cr.connectedWorldEntries?.length) lines.push(`Connected world lore: ${cr.connectedWorldEntries.map(w => `${w.name} [${w.category || "?"}]`).join(", ")}`);
  if (cr.orgPeers?.length) lines.push(`Org peers (same level): ${cr.orgPeers.map(p => p.name).join(", ")}`);
  if (cr.relKeyScenes?.length) lines.push(`Key relationship scenes: ${cr.relKeyScenes.map(s => `with ${s.name}: ${s.scenes}`).join("; ")}`);
  // Motif connections — which motifs are associated with this character
  if (project.motifs?.length > 0) {
    const charName = (project.characters || []).find(c => c.id === charId)?.name;
    if (charName) {
      const charMotifs = (project.motifs || []).filter(m => m.name && (m.appearances || []).some(a => a.context && a.context.toLowerCase().includes(charName.toLowerCase())));
      if (charMotifs.length) lines.push(`Associated motifs: ${charMotifs.map(m => `${m.name} (${m.meaning || "?"})`).join(", ")}`);
    }
  }
  // Thematic role
  if (project.thematicArgument?.embodiedBy?.[charId]) {
    lines.push(`Thematic role: embodies ${project.thematicArgument.embodiedBy[charId]}`);
  }
  // Reader knowledge — what does the reader know about this character?
  if (project.readerKnowledge?.length > 0) {
    const charKnowledge = (project.readerKnowledge || []).filter(rk => rk.fact && (rk.knownBy || []).includes(charId));
    if (charKnowledge.length) lines.push(`Character knows: ${charKnowledge.map(rk => `"${_truncateAtBoundary(rk.fact, 60)}"`).join("; ")}`);
  }
  return lines.join("\n");
};

// Build cross-ref context for a relationship pair
const _buildRelCrossRefContext = (project, relId) => {
  const cr = _deriveCrossRefs(project, null, { relId });
  const lines = [];
  if (cr.relSharedLocs?.length) lines.push(`Shared locations: ${cr.relSharedLocs.map(l => l.name).join(", ")}`);
  if (cr.relSharedOrgs?.length) lines.push(`Same organizations: ${cr.relSharedOrgs.map(o => o.name).join(", ")}`);
  if (cr.relSharedChapters?.length) lines.push(`Together in chapters: ${cr.relSharedChapters.map(p => `Ch${p.chapter || "?"}`).join(", ")}`);
  if (cr.relOrgHierarchy?.length) lines.push(`Org hierarchy: ${cr.relOrgHierarchy.map(h => `${h.subordinate} reports to ${h.superior} in ${h.org}`).join("; ")}`);
  if (cr.relMutualConnections?.length) lines.push(`Mutual connections: ${cr.relMutualConnections.join(", ")}`);
  if (cr.relPersonalityClash) lines.push(`Personality dynamic: "${cr.relPersonalityClash.p1}" vs "${cr.relPersonalityClash.p2}"`);
  if (cr.relFearOverlap?.length) lines.push(`Fears: ${cr.relFearOverlap.map(f => `${f.fearer} fears: ${f.fear}`).join("; ")}`);
  if (cr.relChar1?.status === "dead" || cr.relChar2?.status === "dead") {
    const dead = [cr.relChar1, cr.relChar2].filter(c => c?.status === "dead").map(c => c.name);
    lines.push(`⚠ ${dead.join(" & ")} dead — historical relationship`);
  }
  return lines.join("\n");
};

// Build cross-ref context for a plot entry
const _buildPlotCrossRefContext = (project, plotId) => {
  const cr = _deriveCrossRefs(project, null, { plotId });
  const lines = [];
  if (cr.plotLocDetails?.length) {
    cr.plotLocDetails.forEach(loc => {
      lines.push(`📍 ${loc.name}${loc.atmosphere ? ` — ${loc.atmosphere}` : ""}`);
      if (loc.dangers) lines.push(`  ⚠ Dangers: ${loc.dangers}`);
      if (loc.rules) lines.push(`  📜 Rules: ${loc.rules}`);
      if (loc.sensory) lines.push(`  Sensory: ${loc.sensory}`);
      if (loc.subLocations) lines.push(`  Areas: ${loc.subLocations}`);
      if (loc.charsNotInScene.length) lines.push(`  Also here (not in scene): ${loc.charsNotInScene.join(", ")}`);
    });
  }
  if (cr.plotRelDynamics?.length) {
    lines.push(`Relationship tensions in scene:`);
    cr.plotRelDynamics.forEach(r => {
      let line = `  ${r.c1} ↔ ${r.c2}: ${r.tension || "?"} tension (${r.category || "?"})`;
      if (r.terms) line += ` — address: ${r.terms}`;
      if (r.powerDynamic && r.powerDynamic !== "equal") line += ` — power: ${r.powerDynamic}`;
      if (r.sharedSecrets) line += ` — shared secret: ${_truncateAtBoundary(r.sharedSecrets, 60)}`;
      if (r.taboos) line += ` — taboo: ${r.taboos}`;
      lines.push(line);
    });
  }
  if (cr.plotDeadChars?.length) lines.push(`⚠ Dead characters in scene: ${cr.plotDeadChars.map(c => `${c.name}${c.status && c.status !== "alive" ? ` (${c.status})` : ""}`).join(", ")} — flashback/memory?`);
  if (cr.plotAbsentChars?.length) lines.push(`⚠ Absent characters: ${cr.plotAbsentChars.map(c => c.name).join(", ")}`);
  if (cr.plotOrgContext?.length) lines.push(`Org dynamics: ${cr.plotOrgContext.map(o => `${o.org}: ${o.members.map(m => `${m.name} (${m.title})`).join(", ")}`).join("; ")}`);
  if (cr.plotPrevChapter) lines.push(`Previous: Ch${(cr.plotPrevChapter.title || "?")}: ${cr.plotPrevChapter.summary || "no summary"}`);
  if (cr.plotNextChapter) lines.push(`Next: ${cr.plotNextChapter.title || "?"}`);
  if (cr.plotPovChar) lines.push(`POV character: ${cr.plotPovChar.name} (${cr.plotPovChar.role}) — ${cr.plotPovChar.personality?.split(/[.,;]/)[0]?.trim() || "no personality set"}`);
  return lines.join("\n");
};

const ContextEngine = {
  // D7: Clear POV priority cascade — chapter override > plot outline > project default
  _effectivePov(project, chapterIdx) {
    const ch = project?.chapters?.[chapterIdx];
    const chPov = ch?.pov;
    if (chPov) return chPov;
    // D7: Check plot outline for this chapter's POV
    const chNum = this._chapterNum(project, chapterIdx);
    const plotEntry = (project?.plotOutline || []).find(pl => (pl.chapter || 0) === chNum);
    if (plotEntry?.pov) return plotEntry.pov;
    return project?.pov || "";
  },
  
  // Map array index → actual story chapter number (from linked plot entry)
  _chapterNum(project, chapterIdx) {
    const ch = project?.chapters?.[chapterIdx];
    if (ch?.linkedPlotId) {
      const plot = (project?.plotOutline || []).find(pl => pl.id === ch.linkedPlotId);
      if (plot?.chapter) return plot.chapter;
    }
    return chapterIdx + 1;
  },

  // ─── TIMELINE-AWARE: Parse story dates for chronological comparison ───
  _parseStoryDate(dateStr) {
    if (!dateStr) return null;
    const s = String(dateStr).trim();
    // Handle ambiguous numeric formats (DD/MM/YYYY vs MM/DD/YYYY):
    // If the first number > 12, it MUST be a day → EU format
    // If the second number > 12, first MUST be month → US format
    // ISO format YYYY-MM-DD is unambiguous, handle it first
    const isoMatch = s.match(/^(\d{4})[-/](\d{1,2})[-/](\d{1,2})/);
    if (isoMatch) {
      const y = parseInt(isoMatch[1], 10), m = parseInt(isoMatch[2], 10), d = parseInt(isoMatch[3], 10);
      if (m >= 1 && m <= 12 && d >= 1 && d <= 31) {
        return y * 10000 + m * 100 + d;
      }
    }
    const slashMatch = s.match(/^(\d{1,2})[/-](\d{1,2})[/-](\d{2,4})/);
    if (slashMatch) {
      const a = parseInt(slashMatch[1], 10), b = parseInt(slashMatch[2], 10), c = parseInt(slashMatch[3], 10);
      let y = c < 100 ? 2000 + c : c;
      let month, day;
      if (a > 12) { day = a; month = b; } // must be DD/MM
      else if (b > 12) { month = a; day = b; } // must be MM/DD
      else { month = a; day = b; } // ambiguous — default to MM/DD (US format)
      if (month >= 1 && month <= 12 && day >= 1 && day <= 31) {
        return y * 10000 + month * 100 + day;
      }
    }
    // Try standard date parsing for "Jan 15, 1847", "1847-01-15" etc.
    const d = new Date(s);
    if (!isNaN(d.getTime())) return d.getTime();
    // Try "Year X" or "Year X, Day Y" format (fantasy/sci-fi)
    const yearMatch = s.match(/year\s+(\d+)/i);
    if (yearMatch) {
      const dayMatch = s.match(/day\s+(\d+)/i);
      return parseInt(yearMatch[1], 10) * 10000 + (dayMatch ? parseInt(dayMatch[1], 10) : 0);
    }
    // Try extracting any 4-digit year
    const anyYear = s.match(/\b(\d{4})\b/);
    if (anyYear) return parseInt(anyYear[1], 10) * 10000;
    return null;
  },

  // Get the story date for the current chapter (from plot entry or chapter)
  _currentStoryDate(project, chapterIdx) {
    const plotEntry = this._plotEntryForChapter(project, chapterIdx);
    return this._parseStoryDate(plotEntry?.date);
  },

  // Check if a story date is "before" the current chapter's date
  // Returns true if the event has happened by the current story date
  _hasOccurredByDate(eventDate, eventChapter, currentDate, currentChapter) {
    // If we have dates for both, use date comparison
    if (eventDate && currentDate) return currentDate >= eventDate;
    // Fallback to chapter comparison
    if (eventChapter > 0 && currentChapter > 0) return currentChapter >= eventChapter;
    // If event has a date but current doesn't (or vice versa), fall back to chapter
    return eventChapter > 0 ? currentChapter >= eventChapter : true;
  },

  // Detect if the current chapter is a flashback
  _detectFlashback(project, chapterIdx) {
    // In a non-linear / parallel-timelines project, an earlier story-date does NOT mean a flashback —
    // eras run concurrently and later events deliberately rewrite earlier ones (retrocausality).
    // Suppress flashback detection entirely so it can't inject "don't reference future events".
    if (project?.nonLinearTime) return null;
    const currentDate = this._currentStoryDate(project, chapterIdx);
    if (!currentDate) return null;
    // Find the latest story date from previous chapters
    let latestPrevDate = null;
    for (let i = 0; i < chapterIdx; i++) {
      const d = this._currentStoryDate(project, i);
      if (d && (!latestPrevDate || d > latestPrevDate)) latestPrevDate = d;
    }
    if (latestPrevDate && currentDate < latestPrevDate) {
      return { isFlashback: true, currentDate, latestPrevDate };
    }
    return null;
  },

  // "Has character appeared yet" — uses AI-maintained hasAppeared flag + plot-derived fallback
  _hasAppeared(project, character, chapterIdx, currentChNum) {
    if (!character) return true;
    // Use AI-tracked flag first
    if (character.hasAppeared) return true;
    // Fall back to plot-derived check: does character appear in any plot entry <= current chapter?
    const plots = project?.plotOutline || [];
    return plots.some(pl => {
      const plChNum = pl.chapter || 0;
      return plChNum > 0 && plChNum <= (currentChNum || 0) && Array.isArray(pl.characters) && pl.characters.includes(character.id);
    });
  },

  // "Has character status changed" — just checks status is non-alive
  _hasStatusChanged(project, character, chapterIdx, currentChNum) {
    if (!character) return false;
    return !!(character.status && character.status !== "alive");
  },
  
  // Look up the plot entry for a chapter by its linkedPlotId, falling back to position
  _plotEntryForChapter(project, chapterIdx) {
    const ch = project?.chapters?.[chapterIdx];
    if (!ch) return null;
    
    // First try by linked ID (if it still exists)
    if (ch.linkedPlotId) {
      const byId = (project?.plotOutline || []).find(pl => pl.id === ch.linkedPlotId);
      if (byId) return byId;
      // Linked ID is stale — fall through to chapter number lookup
    }
    
    // Fallback: find by chapter number
    const chNum = this._chapterNum(project, chapterIdx);
    const byChapter = (project?.plotOutline || []).find(pl => (pl.chapter || 0) === chNum);
    if (byChapter) return byChapter;
    
    // Last resort: find ANY plot entry with beats (for legacy data)
    return (project?.plotOutline || []).find(pl => Array.isArray(pl.beats) && pl.beats.length > 0) || null;
  },

  // I4: Better token estimation for structured text — XML tags and field labels tokenize at ~3.3 chars/token
  _estimateLen(text) {
    if (!text) return 0;
    // Detect if text is structured (has XML-like tags or field labels)
    const hasStructure = /<[a-z_]|[A-Z][a-z]+:/.test(text);
    const ratio = hasStructure ? 3.3 : 4;
    return Math.ceil(text.length / ratio);
  },

  // A25/A12/A13: buildMinimalContext now limits to important characters with proper truncation
  buildMinimalContext(project, chapterIdx) {
    if (!project) return "";
    const pov = this._effectivePov(project, chapterIdx);
    const p = [`<novel title="${project.title}">`];
    if (project.genre) p.push(`Genre: ${project.genre}`);
    if (project.tone) p.push(`Tone: ${project.tone}`);
    if (pov) p.push(`POV: ${pov}`);
    if (project.themes) p.push(`Themes: ${project.themes}`);
    if (project.heatLevel != null) p.push(`Heat: ${project.heatLevel}/5`);
    if (project.characters?.length) {
      p.push(`\nCharacters:`);
      // A25: Only include key roles in minimal context, sorted by priority
      const sorted = [...project.characters].sort((a, b) => (ROLE_PRIORITY[a.role] ?? 99) - (ROLE_PRIORITY[b.role] ?? 99));
      const limit = Math.min(sorted.length, 8); // Cap at 8 for minimal
      for (let i = 0; i < limit; i++) {
        const c = sorted[i];
        let desc = `• ${c.name} (${c.role})`;
        if (c.isBulk) { desc += ` [BULK: ${c.bulkCount || "many"} — ${c.bulkDescription || "background"}]`; p.push(desc); continue; }
        if (c.pronouns) desc += ` [${c.pronouns}]`;
        if (c.orientation) desc += ` [${c.orientation}]`;
        // A20: Note dead/absent characters
        if (c.status && c.status !== "alive") desc += ` {${c.status}}`;
        // A12: Truncate personality at sentence/clause boundary
        if (c.personality) desc += ` — ${_truncateAtBoundary(c.personality, 1000)}`;
        // A13: Truncate speech pattern at clause boundary
        if (c.speechPattern) desc += ` | Voice: ${_truncateAtBoundary(c.speechPattern, 1000)}`;
        p.push(desc);
      }
      if (sorted.length > limit) p.push(`  (+ ${sorted.length - limit} more characters)`);
    }
    p.push(`</novel>`);
    return p.join("\n");
  },

  // MASSIVELY REWRITTEN: buildFullContext with temporal awareness, smart filtering, and priority ordering
  // Fixes: A1-A28, B1-B18, C1-C12
  buildFullContext(project, chapterIdx, opts = {}) {
    if (!project) return "";
    const pov = this._effectivePov(project, chapterIdx);
    const tokenBudget = opts.tokenBudget || 24000;
    let tokensUsed = 0;
    const currentChNum = this._chapterNum(project, chapterIdx);

    // ✅ FIX: Declare _charOrgCtx HERE so both characters AND plot sections can use it
    const _charOrgCtx = {};
    (project.worldBuilding || []).forEach(w => {
      if (w.category !== "Organization" || !Array.isArray(w.orgHierarchy)) return;
      w.orgHierarchy.forEach(pos => {
        if (!pos.charId) return;
        const superior = pos.parentId ? w.orgHierarchy.find(p => p.id === pos.parentId) : null;
        const subordinates = w.orgHierarchy.filter(p => p.parentId === pos.id && p.charId);
        if (!_charOrgCtx[pos.charId]) _charOrgCtx[pos.charId] = [];
        _charOrgCtx[pos.charId].push({
          position: pos.name || "Member",
          org: w.name || "Organization",
          reportsTo: superior?.charId ? _resolveCharName(superior.charId, project.characters) : (superior?.name || null),
          manages: subordinates.map(s => s.charId ? _resolveCharName(s.charId, project.characters) : s.name).filter(Boolean),
        });
      });
    });

    // --- Determine scene context for intelligent filtering ---
    const curChapter = project.chapters?.[chapterIdx];
    const sceneNotes = curChapter?.sceneNotes || "";
    // D6: Detect scene type from plot outline. Resolve by linkedPlotId first (robust to plot
    // reordering), then by chapter number. Deliberately NOT using the "any entry with beats"
    // last-resort fallback here — an unrelated entry must never define this chapter's cast.
    const curPlotEntry = (curChapter?.linkedPlotId
      ? (project.plotOutline || []).find(pl => pl.id === curChapter.linkedPlotId)
      : null) || (project.plotOutline || []).find(pl => (pl.chapter || 0) === currentChNum);
    const sceneType = curPlotEntry?.sceneType || "";
    const isIntimateScene = sceneType === "intimate" || /\b(intimate|sex|love\s*scene|bedroom|kiss|sensual)\b/i.test(sceneNotes);
    const isDialogueScene = sceneType === "dialogue" || /\b(conversation|discuss|argue|negotiate|confess|interview)\b/i.test(sceneNotes);
    const isActionScene = sceneType === "action" || sceneType === "tension" || /\b(fight|chase|battle|escape|combat|danger)\b/i.test(sceneNotes);
    const isEmotionalScene = sceneType === "emotional" || /\b(grief|mourn|breakdown|reunion|confront|reveal emotion)\b/i.test(sceneNotes);
    const isRevelationScene = sceneType === "revelation" || /\b(reveal|discover|uncover|truth|secret.*out|twist)\b/i.test(sceneNotes);
    const heatLevel = project.heatLevel || 0;

    // --- Section 1: Core metadata (always included) ---
    const meta = [];
    meta.push(`<novel_bible title="${project.title}">`);
    if (project.synopsis) meta.push(`SYNOPSIS: ${project.synopsis}`);
    if (project.genre) meta.push(`GENRE: ${project.genre}`);
    if (project.tone) meta.push(`TONE/VOICE: ${project.tone}`);
    if (pov) meta.push(`POV: ${pov}${curChapter?.pov ? " (chapter override)" : ""}`);
    if (project.themes) meta.push(`THEMES: ${project.themes}`);
    if (project.heatLevel != null) {
      const labels = ["Fade to black","Suggestive","Moderate explicit","Very explicit","Extremely graphic"];
      meta.push(`HEAT LEVEL: ${project.heatLevel}/5 — ${labels[project.heatLevel - 1] || "Not set"}`);
    }
    if (project.contentPrefs) meta.push(`CONTENT PREFERENCES: ${project.contentPrefs}`);
    if (project.avoidList) meta.push(`HARD LIMITS / AVOID: ${project.avoidList}`);
    // Scene type context modifier
    if (sceneType && sceneType !== "narrative") {
      const sceneGuides = {
        dialogue: "SCENE FOCUS: Dialogue-heavy — prioritize speech patterns, voice, personality. Write distinct voices for each character.",
        action: "SCENE FOCUS: Action/tension — prioritize physicality, skills, environment dangers. Keep prose kinetic.",
        intimate: "SCENE FOCUS: Intimate — prioritize emotional connection, sensory detail, chemistry between characters.",
        tension: "SCENE FOCUS: High tension — prioritize stakes, power dynamics, unspoken subtext, environmental pressure.",
        emotional: "SCENE FOCUS: Emotional — prioritize internal conflict, fears, desires, relationship dynamics.",
        revelation: "SCENE FOCUS: Revelation/twist — build to the reveal carefully. Use dramatic irony if POV character doesn't know yet.",
      };
      if (sceneGuides[sceneType]) meta.push(sceneGuides[sceneType]);
    }
    // ─── TIMELINE-AWARE: Flashback detection ───
    const flashback = this._detectFlashback(project, chapterIdx);
    if (flashback) {
      meta.push(`[FLASHBACK: This chapter is set EARLIER in the story timeline than previous chapters. The reader has already seen future events. Write with dramatic irony — the reader knows what's coming, the characters don't. Do NOT reference events that haven't happened yet in THIS timeline position.]`);
    } else if (project?.nonLinearTime) {
      // Non-linear mode: instead of treating an earlier date as a flashback, tell the model the eras
      // are concurrent and later events may rewrite earlier ones — the retrocausal premise.
      const curDateStr = curPlotEntry?.date || curChapter?.notes?.match(/year\s+\d+/i)?.[0] || "";
      meta.push(`[NON-LINEAR TIMELINE: This story's eras run concurrently, not in sequence. ${curDateStr ? `This chapter is set in ${curDateStr}. ` : ""}A chapter set at an earlier date is NOT a flashback — events in later eras can alter the past (retrocausality). You MAY reference consequences that originate in other eras, even "future" ones, when the story's logic calls for it. Do not flatten this into a single forward-running timeline.]`);
    }
    // ─── NARRATIVE DISTANCE ───
    if (curChapter?.narrativeDistance) {
      const distGuides = {
        "cinematic": "NARRATIVE DISTANCE: Cinematic/wide — describe scenes from outside. Focus on what can be seen, heard, observed. Minimal interiority.",
        "close-third": "NARRATIVE DISTANCE: Close third — stay near the POV character's thoughts but maintain some narrative distance. Balance action and reflection.",
        "deep-interiority": "NARRATIVE DISTANCE: Deep interiority — live inside the POV character's head. Stream of consciousness, raw thought, sensory immediacy. Minimal exposition.",
      };
      if (distGuides[curChapter.narrativeDistance]) meta.push(distGuides[curChapter.narrativeDistance]);
    }
    // ─── SENSORY PALETTE ───
    if (curChapter?.sensoryPalette) {
      meta.push(`SENSORY PALETTE: ${curChapter.sensoryPalette} — weight descriptions toward these sensory elements.`);
    }
    // ─── SUBTEXT ───
    if (curChapter?.subtextNotes) {
      meta.push(`SUBTEXT: ${curChapter.subtextNotes} — this is what's happening beneath the surface. Characters may not say what they mean.`);
    }
    if (Array.isArray(curChapter?.subtextLines) && curChapter.subtextLines.length) {
      const pairs = curChapter.subtextLines.slice(0, 8).map(sl => `"${sl.line}" → really means: ${sl.subtext}`).join("; ");
      meta.push(`DIALOGUE SUBTEXT (say one thing, mean another): ${pairs}`);
    }
    // ─── WORLD-STATE LEDGER ───
    // Global conditions triggered at a chapter persist into all later chapters, so the AI keeps
    // ambient reality consistent (a war from Ch12 means scarcer food / tenser mood afterward).
    if (Array.isArray(project.worldStateLedger) && project.worldStateLedger.length) {
      const active = project.worldStateLedger
        .filter(e => (e.fromChapter ?? 0) <= currentChNum)
        .map(e => `${e.condition}${e.description ? ` (${e.description})` : ""} [since Ch${(e.fromChapter ?? 0) + 1}]`);
      if (active.length) meta.push(`ACTIVE WORLD CONDITIONS — reflect these in ambient description: ${active.join("; ")}`);
    }
    // ─── CHARACTER PHYSICAL/STATE CONTINUITY ───
    // Per-character states (injuries, conditions) active in this chapter window. Injected so the AI
    // honors them (a broken arm in Ch3 shouldn't be throwing punches in Ch5 unless it's healed).
    if (Array.isArray(project.characters)) {
      const stateLines = [];
      for (const c of project.characters) {
        if (!Array.isArray(c.stateFlags)) continue;
        for (const sf of c.stateFlags) {
          const from = sf.fromChapter ?? 0;
          const until = sf.untilChapter != null && sf.untilChapter !== "" ? sf.untilChapter : Infinity;
          if (from <= currentChNum && currentChNum <= until) {
            stateLines.push(`${c.name}: ${sf.state}${sf.untilChapter != null && sf.untilChapter !== "" ? ` (until Ch${sf.untilChapter + 1})` : " (ongoing)"}`);
          }
        }
      }
      if (stateLines.length) meta.push(`CHARACTER PHYSICAL STATE (must stay consistent): ${stateLines.join("; ")}`);
    }
    // ─── MOTIFS & SYMBOLS ───
    if (project.motifs?.length > 0) {
      const relevantMotifs = (project.motifs || []).filter(m => m.name && (m.appearances || []).some(a => a.chapter <= currentChNum));
      if (relevantMotifs.length > 0) {
        meta.push(`MOTIFS/SYMBOLS (weave naturally): ${relevantMotifs.map(m => `${m.name} (${m.meaning || "meaning TBD"}${m.evolution ? ` → evolves: ${_truncateAtBoundary(m.evolution, 80)}` : ""})`).join("; ")}`);
      }
    }
    // ─── THEMATIC ARGUMENT ───
    if (project.thematicArgument?.thesis) {
      const ta = project.thematicArgument;
      let thematicLine = `THEMATIC ARGUMENT: Thesis: "${ta.thesis}"`;
      if (ta.antithesis) thematicLine += ` | Antithesis: "${ta.antithesis}"`;
      if (ta.synthesis) thematicLine += ` | Synthesis: "${ta.synthesis}"`;
      // Which characters embody which side
      if (ta.embodiedBy && Object.keys(ta.embodiedBy).length > 0) {
        const chars = project.characters || [];
        const sides = Object.entries(ta.embodiedBy).map(([cid, side]) => {
          const ch = chars.find(c => c.id === cid);
          return ch ? `${ch.name} embodies ${side}` : null;
        }).filter(Boolean);
        if (sides.length) thematicLine += ` | ${sides.join(", ")}`;
      }
      meta.push(thematicLine);
    }
    // ─── READER KNOWLEDGE STATE ───
    if (project.readerKnowledge?.length > 0) {
      const knownFacts = (project.readerKnowledge || []).filter(rk => {
        if (!rk.fact) return false;
        const revealDate = this._parseStoryDate(rk.revealedDate);
        const currentDate = this._currentStoryDate(project, chapterIdx);
        return this._hasOccurredByDate(revealDate, rk.revealedInChapter || 0, currentDate, currentChNum);
      });
      if (knownFacts.length > 0) {
        meta.push(`READER KNOWLEDGE (the reader knows these facts): ${knownFacts.map(rk => {
          const knownByNames = (rk.knownBy || []).map(cid => (project.characters || []).find(c => c.id === cid)?.name).filter(Boolean);
          return `"${_truncateAtBoundary(rk.fact, 80)}"${knownByNames.length ? ` (known by: ${knownByNames.join(", ")})` : " (no characters know this yet)"}`;
        }).join("; ")}`);
      }
    }
    if (project.writingStyle) meta.push(`WRITING STYLE NOTES: ${project.writingStyle}`);
    if (project.continuityNotes) {
      // I8: If continuity notes contain chapter-scoped entries (e.g., "Ch5: Elena gets the scar"),
      // filter to only show entries relevant to the current chapter or earlier
      const lines = project.continuityNotes.split("\n").filter(l => l.trim());
      const relevantLines = [];
      for (const line of lines) {
        const chMatch = line.match(/^(?:•\s*)?Ch(?:apter)?\s*(\d+)\s*[:\-–—]/i);
        if (chMatch) {
          const entryChapter = parseInt(chMatch[1], 10);
          // Only include entries from the current chapter or earlier (no future spoilers)
          if (entryChapter <= currentChNum) relevantLines.push(line.trim());
        } else {
          // Non-chapter-scoped entries are always included
          relevantLines.push(line.trim());
        }
      }
      if (relevantLines.length > 0) {
        meta.push(`\n<continuity_notes>\n${relevantLines.join("\n")}\n</continuity_notes>`);
      }
    }

    const metaStr = meta.join("\n");
    tokensUsed += this._estimateLen(metaStr);

    // I2: Explicit budget segment allocations (not overlapping cumulative caps)
    const remainingBudget = tokenBudget - tokensUsed;
    const budgetChars = tokensUsed + Math.floor(remainingBudget * 0.40); // chars can use up to 40% of remaining
    const budgetRels = budgetChars + Math.floor(remainingBudget * 0.15); // rels get 15%
    const budgetWorld = budgetRels + Math.floor(remainingBudget * 0.20); // world gets 20%
    const budgetPlot = budgetWorld + Math.floor(remainingBudget * 0.20); // plot gets 20%
    // 5% buffer remains unused

    // --- Detect relevant entities --- A7: Include plot beats in detection text
    const curPlain = curChapter?.content ? _htmlToPlain(curChapter.content) : "";
    const plotBeats = curPlotEntry ? `${curPlotEntry.title || ""} ${curPlotEntry.summary || ""} ${curPlotEntry.beats || ""}` : "";
    const detectionText = curPlain + " " + sceneNotes + " " + plotBeats;

    const mentionedCharIds = _detectMentionedCharacters(detectionText, project.characters);

    // The Plot tab's `characters` array is the AUTHOR'S explicit statement of who is in this
    // chapter. When it's non-empty, it is authoritative: those characters are present, and any
    // other character merely detected in the prose is at most "referenced" (talked about), never
    // auto-promoted into the scene. When it's empty, we fall back to prose detection + heuristics.
    const forcedPresentIds = new Set();
    const plotCharIds = Array.isArray(curPlotEntry?.characters)
      ? curPlotEntry.characters.filter(cid => (project.characters || []).some(c => c.id === cid))
      : [];
    const authorCuratedCast = plotCharIds.length > 0;
    for (const cid of plotCharIds) {
      mentionedCharIds.add(cid);
      forcedPresentIds.add(cid); // author tagged them for the scene → definitely present
    }
    // Characters named in the scene notes are authorial intent → present.
    if (sceneNotes) {
      const noteIds = _detectMentionedCharacters(sceneNotes, project.characters);
      noteIds.forEach(id => { mentionedCharIds.add(id); forcedPresentIds.add(id); });
    }

    const relevantWorldIds = _detectRelevantWorld(detectionText, project.worldBuilding);

    // NEW: Inject plot-selected locations into relevant world IDs
    if (curPlotEntry?.locations) {
      const plotLocIds = Array.isArray(curPlotEntry.locations) ? curPlotEntry.locations : [];
      for (const lid of plotLocIds) {
        if ((project.worldBuilding || []).some(w => w.id === lid)) {
          relevantWorldIds.add(lid);
        }
      }
    }

    // NEW: Collect "ambient" characters — characters who frequent relevant locations
    // but are NOT explicitly mentioned or plot-selected. These get compact treatment.
    const ambientCharIds = new Set();
    if (project.worldBuilding?.length) {
      for (const wid of relevantWorldIds) {
        const w = project.worldBuilding.find(we => we.id === wid);
        if (w && Array.isArray(w.frequentCharacters)) {
          for (const cid of w.frequentCharacters) {
            // Only add if they're not already explicitly mentioned
            if (!mentionedCharIds.has(cid) && (project.characters || []).some(c => c.id === cid)) {
              ambientCharIds.add(cid);
            }
          }
        }
      }
    }

    // A22: Identify POV character — FIX: Multi-strategy detection
    let povCharId = null;
    // Strategy 0 (highest priority): Explicit POV character ID from plot outline
    if (curPlotEntry?.povCharacterId) {
      const match = (project.characters || []).find(c => c.id === curPlotEntry.povCharacterId);
      if (match) povCharId = match.id;
    }
    // Strategy 1: Extract character name from POV string like "Third person limited - Elena"
    if (!povCharId) {
      const povString = curChapter?.pov || project?.pov || "";
      const povCharName = _stripPovPrefix(povString);
      if (povCharName && povCharName.length > 1) {
        const exactMatch = (project.characters || []).find(c => c.name && c.name.toLowerCase() === povCharName.toLowerCase());
        const partialMatch = !exactMatch && (project.characters || []).find(c => c.name && (
          c.name.toLowerCase().startsWith(povCharName.toLowerCase()) ||
          c.name.split(/\s+/)[0].toLowerCase() === povCharName.toLowerCase()
        ));
        if (exactMatch) povCharId = exactMatch.id;
        else if (partialMatch) povCharId = partialMatch.id;
      }
    }
    // Strategy 2: Check plot outline for this chapter's POV character field (if it stores a char name)
    if (!povCharId && curPlotEntry?.pov) {
      const plotPovName = curPlotEntry.pov.replace(/^(Third person|First person|Second person|Multiple|Dual)[^-—:]*[-—:]\s*/i, "").trim();
      if (plotPovName && plotPovName.length > 1) {
        const match = (project.characters || []).find(c => c.name && c.name.toLowerCase().startsWith(plotPovName.toLowerCase()));
        if (match) povCharId = match.id;
      }
    }
    // Strategy 3: Fall back to protagonist if no POV character identified
    if (!povCharId) {
      const protagonist = (project.characters || []).find(c => c.role === "protagonist");
      if (protagonist) povCharId = protagonist.id;
    }

    // POV character is, by definition, present in their own scene.
    if (povCharId) forcedPresentIds.add(povCharId);
    // Determine present vs referenced-absent.
    let presentCharIds, referencedCharIds;
    if (authorCuratedCast) {
      // Author curated the cast → it is authoritative. Present = the curated list (+ POV + scene
      // notes). Any OTHER character merely detected in the prose is "referenced" (talked about),
      // never auto-added to the scene.
      presentCharIds = new Set(forcedPresentIds);
      referencedCharIds = new Set();
      for (const id of mentionedCharIds) {
        if (!presentCharIds.has(id)) referencedCharIds.add(id);
      }
    } else {
      // No curated cast → fall back to prose detection + presence heuristics.
      const classified = _classifyCharacterPresence(detectionText, project.characters, mentionedCharIds, { forcedPresent: forcedPresentIds, relaxAbsence: !!project.nonLinearTime });
      presentCharIds = classified.present;
      referencedCharIds = classified.referenced;
    }

    // --- Sections 2-5 extracted into helpers operating on a shared ctx bag ---
    const ctx = {
      project, chapterIdx, opts, currentChNum, _charOrgCtx,
      sceneType, isIntimateScene, isDialogueScene, isActionScene, isEmotionalScene, isRevelationScene,
      heatLevel, mentionedCharIds, presentCharIds, referencedCharIds, ambientCharIds, relevantWorldIds, povCharId, curPlotEntry,
      budgetChars, budgetRels, budgetWorld, budgetPlot,
      tokensUsed,
    };
    const charParts = this._sectionCharacters(ctx);
    const relParts = this._sectionRelationships(ctx);
    const worldParts = this._sectionWorld(ctx);
    const plotParts = this._sectionPlot(ctx);
    tokensUsed = ctx.tokensUsed;
    const sections = [metaStr, ...charParts, ...relParts, ...worldParts, ...plotParts, `</novel_bible>`];
    // Context size safety check
    const totalEstimate = sections.reduce((sum, s) => sum + (s?.length || 0), 0);
    if (totalEstimate > 200000) {
      console.warn(`[NovelForge] Context is very large (~${Math.round(totalEstimate/1000)}k chars / ~${Math.round(totalEstimate/4)}  tokens). May exceed model limits.`);
    }
    return sections.filter(s => s).join("\n");
  },

  // ─── _sectionCharacters (extracted from buildFullContext; shared ctx bag) ───
  _sectionCharacters(ctx) {
    const {
      project, chapterIdx, currentChNum, _charOrgCtx,
      isIntimateScene, isDialogueScene, isActionScene, isEmotionalScene, isRevelationScene,
      heatLevel, mentionedCharIds, ambientCharIds, relevantWorldIds, povCharId, budgetChars,
    } = ctx;
    // Presence sets (may be absent on older callers → fall back to "all mentioned are present").
    const presentCharIds = ctx.presentCharIds || mentionedCharIds;
    const referencedCharIds = ctx.referencedCharIds || new Set();
    // --- Section 2: Characters (priority-sorted, temporally-aware) ---
    const charParts = [];
    if (project.characters?.length) {
      charParts.push(`\n<characters>`);

      // A9: Fields to include vary by scene context
      const getCharFields = (c, isInScene) => {
        const fields = [];
        if (c.aliases) fields.push(["Also known as", c.aliases]);
        if (c.gender) fields.push(["Gender", c.gender]);
        if (c.age) fields.push(["Age", `${c.age}${c.hasAppeared ? ` (as of story start)` : ""}`]); // A15
        if (c.pronouns) fields.push(["Pronouns", c.pronouns]);
        if (c.orientation) fields.push(["Orientation", c.orientation]);
        // Bulk character group — abbreviated output
        if (c.isBulk) {
          fields.push(["[BULK GROUP]", `${c.bulkCount || "many"} individuals — ${c.bulkDescription || c.personality || "background characters"}`]);
        }
        // A16: Note if gender/pronouns mismatch conventionally
        if (c.gender && c.pronouns) {
          const genderLower = c.gender.toLowerCase();
          const pronounLower = c.pronouns.toLowerCase();
          const mismatch = (genderLower === "male" && pronounLower.startsWith("she/")) || (genderLower === "female" && pronounLower.startsWith("he/"));
          if (mismatch) fields.push(["[Note]", "Gender/pronoun combination is intentional — do not 'correct'"]);
        }
        if (c.occupation) fields.push(["Occupation", c.occupation]);
        // Inject org hierarchy positions — also derive occupation if not manually set
        if (_charOrgCtx[c.id]) {
          _charOrgCtx[c.id].forEach(org => {
            let orgLine = `${org.position} in ${org.org}`;
            if (org.reportsTo) orgLine += ` — reports to ${org.reportsTo}`;
            if (org.manages.length > 0) orgLine += ` — manages ${org.manages.join(", ")}`;
            fields.push(["Org rank", orgLine]);
          });
          if (!c.occupation && _charOrgCtx[c.id].length > 0) {
            fields.push(["Occupation", _charOrgCtx[c.id].map(o => `${o.position} (${o.org})`).join(", ")]);
          }
        }
        // Inject location context — where this character is typically found
        const charLocs = (project.worldBuilding || []).filter(w =>
          (w.category === "Location" || !w.category) && Array.isArray(w.frequentCharacters) && w.frequentCharacters.includes(c.id) && w.name
        );
        if (charLocs.length > 0) {
          fields.push(["Frequents", charLocs.map(l => l.name).join(", ")]);
        }
        if (c.height) fields.push(["Height", c.height]);
        if (c.build) fields.push(["Build", c.build]);
        // A10: Compact appearance after first few chapters
        if (c.appearance) {
          // Derive first appearance chapter from plot outline
          const firstPlotCh = (project.plotOutline || []).filter(pl => Array.isArray(pl.characters) && pl.characters.includes(c.id)).map(pl => pl.chapter || 0).filter(n => n > 0).sort((a,b) => a-b)[0];
          if (firstPlotCh && currentChNum > firstPlotCh + 2) {
            fields.push(["Appearance (key)", _truncateAtBoundary(c.appearance, 1000)]);
          } else {
            fields.push(["Appearance", c.appearance]);
          }
        }
        if (c.personality) fields.push(["Personality", c.personality]);
        if (c.fears) fields.push(["Fears", c.fears]);
        if (c.flaws) fields.push(["Flaws", c.flaws]);
        if (c.strengths) fields.push(["Strengths", c.strengths]);
        if (c.skills) fields.push(["Skills/Abilities", c.skills]);
        if (c.habits) fields.push(["Habits/Mannerisms", c.habits]);
        // A2: Backstory gated by reveal chapter OR reveal date (timeline-aware)
        if (c.backstory) {          const curDate = ContextEngine._currentStoryDate(project, chapterIdx);
          if (!c.backstoryRevealed) {
            fields.push(["Backstory", "[UNREVEALED — will be revealed later. Do NOT hint at or reference backstory details.]"]);
          } else {
            fields.push(["Backstory", c.backstory]);
          }
        }
        // Secrets — gated like backstory (date-aware)
        if (c.secrets) fields.push(["Known Secrets", c.secrets]);
        if (c.hiddenSecrets) {          const sCurDate = ContextEngine._currentStoryDate(project, chapterIdx);
          if (!c.secretRevealed) {
            fields.push(["Hidden Secrets", "[UNREVEALED — Do NOT hint at these secrets yet.]"]);
          } else {
            fields.push(["Hidden Secrets (NOW REVEALED)", c.hiddenSecrets]);
          }
        }
        // A3: Desires with temporal context
        if (c.desires) {
          fields.push(["Desires/Motivations", `${c.desires} [Note: Desires evolve — cross-reference with chapter content for current state]`]);
        }
        if (c.shortTermGoals) fields.push(["Short-term Goals", c.shortTermGoals]);
        if (c.longTermGoals) fields.push(["Long-term Goals", c.longTermGoals]);
        if (c.internalConflict) fields.push(["Internal Conflict", c.internalConflict]);
        if (c.externalConflict) fields.push(["External Conflict", c.externalConflict]);
        if (c.speechPattern) fields.push(["Speech pattern", c.speechPattern]);
        if (c.voiceSamples) fields.push(["Voice samples", c.voiceSamples]);
        if (c.signatureItems) fields.push(["Signature items", c.signatureItems]);
        if (c.allegiances) fields.push(["Allegiances", c.allegiances]);
        if (c.tags) fields.push(["Traits", c.tags]);
        // A8: Only include character's relationships text if no Relationships tab entries exist for this character
        if (c.relationships) {
          const hasRelEntries = (project.relationships || []).some(r => {
            const c1Id = _resolveCharId(r.char1, project.characters);
            const c2Id = _resolveCharId(r.char2, project.characters);
            return c1Id === c.id || c2Id === c.id;
          });
          if (!hasRelEntries) {
            fields.push(["Relationships", c.relationships]);
          }
        }
        // A9: Only include kinks for intimate scenes or high heat
        if (c.kinks && (isIntimateScene || heatLevel >= 3)) {
          fields.push(["Preferences", c.kinks]);
        }
        // A1: Arc with temporal position — describe where character IS, not full trajectory
        if (c.arc) {
          const totalChapters = project.chapters?.length || 1;
          const progress = Math.min(1, currentChNum / Math.max(totalChapters, 1));
          let arcPhase = "early";
          if (progress > 0.75) arcPhase = "late";
          else if (progress > 0.5) arcPhase = "mid-to-late";
          else if (progress > 0.25) arcPhase = "mid";
          fields.push(["Character arc", `[Story position: ${arcPhase}, Ch${currentChNum}/${totalChapters}] ${c.arc}`]);
        }
        // A17: Canon notes — FIX 1.22: truncate long canon notes
        if (c.canonNotes) fields.push(["Canon notes", _truncateAtBoundary(c.canonNotes, 1000)]);
        // Scene-type-aware emphasis notes
        if (isDialogueScene && c.speechPattern) fields.push(["[SCENE NOTE]", "Dialogue scene — maintain this character's distinct voice throughout"]);
        if (isActionScene && c.skills) fields.push(["[SCENE NOTE]", "Action scene — leverage this character's skills and physical capabilities"]);
        if (isEmotionalScene && (c.fears || c.internalConflict)) fields.push(["[SCENE NOTE]", "Emotional scene — explore this character's inner world and vulnerabilities"]);
        if (isRevelationScene && (c.hiddenSecrets || c.backstory)) fields.push(["[SCENE NOTE]", "Revelation scene — what this character knows or discovers matters"]);
        // A20: Status — FIX 1.28: Note "unknown" status explicitly
        if (c.status && c.status !== "alive") {
          let statusNote = c.status.toUpperCase();
          // Status change tracking is AI-maintained
          if (c.status === "unknown") statusNote += " — fate uncertain, write accordingly";
          fields.push(["Status", statusNote]);
        }
        return fields;
      };

      // A19: Sort by role importance, then mentioned first
      const allChars = [...project.characters].sort((a, b) => {
        // POV character always first
        if (a.id === povCharId) return -1;
        if (b.id === povCharId) return 1;
        // Mentioned characters before non-mentioned
        const aMentioned = mentionedCharIds.has(a.id) ? 0 : 1;
        const bMentioned = mentionedCharIds.has(b.id) ? 0 : 1;
        if (aMentioned !== bMentioned) return aMentioned - bMentioned;
        // Then by role priority
        return (ROLE_PRIORITY[a.role] ?? 99) - (ROLE_PRIORITY[b.role] ?? 99);
      });

      const mentioned = allChars.filter(c => presentCharIds.has(c.id));
      const referencedOnly = allChars.filter(c => referencedCharIds.has(c.id) && !presentCharIds.has(c.id));
      const others = allChars.filter(c => !mentionedCharIds.has(c.id));

      // Full detail for present/in-scene characters
      for (const c of mentioned) {
        // FIX 1.6: Dead characters get compact treatment starting from the chapter AFTER death
        if (c.status === "dead" && ContextEngine._hasStatusChanged(project, c, chapterIdx, currentChNum)) {
          // Dead — include only as compact reference (mentioned because of memory/flashback)
          let compact = `  ○ ${c.name} (${c.role}) [DECEASED] — referenced in scene as memory/mention only`;
          if (c.pronouns) compact += ` [${c.pronouns}]`;
          charParts.push(compact);
          ctx.tokensUsed += this._estimateLen(compact);
          continue;
        }
        const isPov = c.id === povCharId;
        const tag = isPov ? "[POV CHARACTER]" : "[IN SCENE]";
        const l = [`★ ${c.name} (${c.role || "supporting"}) ${tag}`];
        const fields = getCharFields(c, true);
        fields.forEach(([label, val]) => l.push(`  ${label}: ${val}`));
        const entry = l.join("\n");
        if (ctx.tokensUsed + this._estimateLen(entry) < budgetChars) {
          charParts.push(entry);
          ctx.tokensUsed += this._estimateLen(entry);
        }
      }

      // Referenced but NOT present — talked about / remembered / absent. The writing AI should
      // NOT place these characters in the scene; they're context for what's being discussed.
      if (referencedOnly.length) {
        charParts.push(`\n— Referenced but NOT in the scene (talked about / remembered — do not place them physically in this scene):`);
        for (const c of referencedOnly) {
          const statusTag = (c.status && c.status !== "alive") ? ` {${c.status}}` : "";
          let line = `  ◇ ${c.name} (${c.role || "supporting"})${statusTag}`;
          if (c.pronouns) line += ` [${c.pronouns}]`;
          if (c.personality) line += ` — ${_truncateAtBoundary(c.personality, 160)}`;
          if (c.occupation) line += ` | ${c.occupation}`;
          if (ctx.tokensUsed + this._estimateLen(line) < budgetChars) {
            charParts.push(line);
            ctx.tokensUsed += this._estimateLen(line);
          }
        }
      }

      // A6: Compact entries for non-scene characters — BUT only if they've been introduced
      // FIX: Don't dump ALL characters. Only include characters who:
      // 1. Have appeared by this chapter (hasAppeared flag or plot-derived)
      // 2. Are key roles (protagonist, antagonist, love interest, deuteragonist) OR
      //    appeared in recent chapters (within lookback window)
      if (others.length) {
        const keyRoles = new Set(["protagonist", "antagonist", "love interest", "deuteragonist", "villain"]);
        // Detect characters in recent chapter summaries ONCE (shared detector → consistent guards).
        const recentSummaries = (project.chapters || []).slice(Math.max(0, chapterIdx - 3), chapterIdx)
          .map(ch => ch.summary || "").join(" ");
        const recentSummaryIds = recentSummaries ? _detectMentionedCharacters(recentSummaries, project.characters) : new Set();
        // Determine which non-scene characters are relevant enough to include
        const relevantOthers = others.filter(c => {
          // Filter out characters not yet introduced
          if (!ContextEngine._hasAppeared(project, c, chapterIdx, currentChNum) && (c.hasAppeared || (project.plotOutline || []).some(pl => Array.isArray(pl.characters) && pl.characters.includes(c.id)))) return false;
          // Always include key roles
          if (keyRoles.has(c.role)) return true;
          // Include if detected in recent chapter summaries.
          if (recentSummaryIds.has(c.id)) return true;
          return false;
        });

        if (relevantOthers.length) {
          charParts.push(`\n— Other characters (not in current scene):`);
          for (const c of relevantOthers) {
            // A20: Note dead/absent characters clearly
            const statusTag = (c.status && c.status !== "alive") ? ` {${c.status}}` : "";
            let compact = `  • ${c.name} (${c.role || "supporting"})${statusTag}`;
            if (c.pronouns) compact += ` [${c.pronouns}]`;
            // A12: Sentence-boundary truncation for personality
            if (c.personality) compact += ` — ${_truncateAtBoundary(c.personality, 1000)}`;
            // A6: Include speech pattern snippet for characters who might speak
            if (c.speechPattern) compact += ` | Voice: ${_truncateAtBoundary(c.speechPattern, 1000)}`;
            if (c.occupation) compact += ` | ${c.occupation}`;
            if (c.aliases) compact += ` | AKA: ${c.aliases}`;
            if (c.allegiances) compact += ` | Loyal to: ${c.allegiances}`;
            if (c.desires && keyRoles.has(c.role)) compact += ` | Wants: ${_truncateAtBoundary(c.desires, 100)}`;
            // A1: Arc phase only (no full arc text)
            if (c.arc) {
              const totalCh = project.chapters?.length || 1;
              const prog = Math.min(1, currentChNum / Math.max(totalCh, 1));
              const phase = prog > 0.75 ? "late" : prog > 0.5 ? "mid-to-late" : prog > 0.25 ? "mid" : "early";
              compact += ` | Arc phase: ${phase}`;
            }
            if (ctx.tokensUsed + this._estimateLen(compact) < budgetChars) {
              charParts.push(compact);
              ctx.tokensUsed += this._estimateLen(compact);
            }
          }
          const omittedCount = others.length - relevantOthers.length;
          if (omittedCount > 0) {
            charParts.push(`  (+ ${omittedCount} other characters not yet relevant to this chapter)`);
          }
        }
      }

      // NEW: Ambient characters — frequent this location but NOT in scene
      // Ultra-compact: ONE line each. Instruction goes in section header, not per character.
      if (ambientCharIds.size > 0) {
        const ambientChars = (project.characters || []).filter(c => ambientCharIds.has(c.id));
        const livingAmbient = ambientChars.filter(c => {
          if (c.status === "dead") return false;
          if (!ContextEngine._hasAppeared(project, c, chapterIdx, currentChNum) && (c.hasAppeared || (project.plotOutline || []).some(pl => Array.isArray(pl.characters) && pl.characters.includes(c.id)))) return false;
          return true;
        });
        if (livingAmbient.length > 0) {
          const locNames = [];
          for (const wid of relevantWorldIds) {
            const w = (project.worldBuilding || []).find(we => we.id === wid);
            if (w && Array.isArray(w.frequentCharacters) && w.frequentCharacters.some(cid => ambientCharIds.has(cid))) {
              locNames.push(w.name);
            }
          }
          charParts.push(`\n— Nearby (at ${locNames.join("/") || "location"} — may appear naturally, not the focus):`);
          for (const c of livingAmbient) {
            // TRUE one-liner: "Name (role, pronoun) — 6-word personality max"
            let line = `  ◦ ${c.name}`;
            const meta = [c.role || "supporting", c.pronouns, c.occupation].filter(Boolean).join(", ");
            line += ` (${meta})`;
            // Personality: max ~8 words, hard truncate
            if (c.personality) {
              const words = c.personality.split(/\s+/).slice(0, 8).join(" ");
              line += ` — ${words}${c.personality.split(/\s+/).length > 8 ? "…" : ""}`;
            }
            if (ctx.tokensUsed + this._estimateLen(line) < budgetChars) {
              charParts.push(line);
              ctx.tokensUsed += this._estimateLen(line);
            }
          }
        }
      }
      // A18: Name list only for characters who have been introduced
      const introducedNames = project.characters
        .filter(c => c.name && ContextEngine._hasAppeared(project, c, chapterIdx, currentChNum))
        .map(c => c.name).join(", ");
      if (introducedNames) charParts.push(`\n[Known characters: ${introducedNames}]`);
      charParts.push(`</characters>`);
    }

     return charParts;
  },

  // ─── _sectionRelationships (extracted from buildFullContext; shared ctx bag) ───
  _sectionRelationships(ctx) {
    const { project, currentChNum, mentionedCharIds, povCharId, budgetRels } = ctx;
    // --- Section 3: Relationships (evolution-aware, filtered) --- B1-B18
    // FIX: Use ID-based matching for relationships, resolve to names for display
    const relParts = [];
    if (project.relationships?.length) {
      const chars = project.characters || [];
      const relevantRels = project.relationships.filter(r => {
        // B13: Don't include relationships where characters haven't met yet
        if (r.meetsInChapter > 0 && currentChNum < r.meetsInChapter) return false;
        // FIX: Resolve char1/char2 as IDs (with fallback to name matching for legacy data)
        const c1Id = _resolveCharId(r.char1, chars);
        const c2Id = _resolveCharId(r.char2, chars);
        // Skip empty relationships
        if (!c1Id && !c2Id) return false;
        // B5: When no characters detected, use POV character relationships or key roles only
        if (mentionedCharIds.size === 0) {
          if (povCharId) {
            return c1Id === povCharId || c2Id === povCharId;
          }
          const keyRoles = new Set(["protagonist", "antagonist", "love interest"]);
          return chars.some(c => keyRoles.has(c.role) && (c.id === c1Id || c.id === c2Id));
        }
        // B4: Include if either character is mentioned
        return mentionedCharIds.has(c1Id) || mentionedCharIds.has(c2Id);
      });

      if (relevantRels.length) {
        relParts.push(`\n<relationships>`);
        relevantRels.forEach(r => {
          // FIX: Resolve IDs to names for display in context
          const c1Name = _resolveCharName(r.char1, chars);
          const c2Name = _resolveCharName(r.char2, chars);
          // B2/B3: Include temporal scope and tension type
          let line = `${c1Name} ↔ ${c2Name}: ${r.dynamic}`;
          if (r.category && r.category !== "romantic") line += ` | Category: ${r.category}`;
          if (r.status) line += ` | Status: ${r.status}`;
          if (r.tension) {
            line += ` | Tension: ${r.tension}`;
            if (r.tensionType) line += ` (${r.tensionType})`; // B3: Tension flavor
          }
          if (r.powerDynamic && r.powerDynamic !== "equal") line += ` | Power: ${r.powerDynamic}`;
          if (r.trustLevel) line += ` | Trust: ${r.trustLevel}`;
          if (r.terms) line += ` | Address: ${r.terms}`;
          if (r.isPublic === false) line += ` | [SECRET — other characters don't know]`;
          // B7: Directional perspectives
          if (r.char1Perspective) line += ` | ${c1Name}'s view: ${_truncateAtBoundary(r.char1Perspective, 1000)}`;
          if (r.char2Perspective) line += ` | ${c2Name}'s view: ${_truncateAtBoundary(r.char2Perspective, 1000)}`;
          if (r.chemistry) line += ` | Chemistry: ${_truncateAtBoundary(r.chemistry, 200)}`;
          if (r.conflictSource) line += ` | Conflict: ${_truncateAtBoundary(r.conflictSource, 200)}`;
          if (r.sharedSecrets) line += ` | Shared secrets: ${_truncateAtBoundary(r.sharedSecrets, 200)}`;
          if (r.taboos) line += ` | Taboos: ${r.taboos}`;
          // Auto-derived: shared locations and orgs between these two characters
          const _sharedLocs = (project.worldBuilding || []).filter(w =>
            (w.category === "Location" || !w.category) && Array.isArray(w.frequentCharacters) &&
            w.frequentCharacters.includes(r.char1) && w.frequentCharacters.includes(r.char2) && w.name
          ).map(w => w.name);
          if (_sharedLocs.length) line += ` | Shared locations: ${_sharedLocs.join(", ")}`;
          // B10: Progression arc
          if (r.progression) line += ` | Arc: ${r.progression}`;
          // Key scenes relevant to current chapter
          if (r.keyScenes) line += ` | Key scenes: ${_truncateAtBoundary(r.keyScenes, 300)}`;
          // B1/B2: Evolution timeline with chapter awareness
          if (r.evolutionTimeline) {
            line += ` | Evolution: ${_truncateAtBoundary(r.evolutionTimeline, 1000)}`;
          }
          // B6: Sentence-boundary truncation for notes
          if (r.notes) line += ` | ${_truncateAtBoundary(r.notes, 1000)}`;
          // AI-tracked per-chapter evolution (written by the stateUpdater agent). Surface the most
          // recent snapshot AT OR BEFORE the current chapter so the writer sees where the
          // relationship actually stands now, not just the static authored fields.
          if (r.chapterEvolution && typeof r.chapterEvolution === "object") {
            const keys = Object.keys(r.chapterEvolution).map(Number).filter(n => !isNaN(n) && n <= currentChNum).sort((a, b) => b - a);
            if (keys.length > 0) {
              const latest = r.chapterEvolution[keys[0]];
              const evoBits = [];
              if (latest.status) evoBits.push(`status ${latest.status}`);
              if (latest.tension) evoBits.push(`tension ${latest.tension}`);
              if (latest.trustLevel) evoBits.push(`trust ${latest.trustLevel}`);
              if (latest.progression) evoBits.push(_truncateAtBoundary(latest.progression, 120));
              if (evoBits.length) line += ` | Current state (as of Ch${keys[0]}): ${evoBits.join(", ")}`;
            }
          }
          if (ctx.tokensUsed + this._estimateLen(line) < budgetRels) {
            relParts.push(line);
            ctx.tokensUsed += this._estimateLen(line);
          }
        });
        relParts.push(`</relationships>`);
      }
      // B12: List character pairs for non-included relationships (not just a count)
      const otherRels = project.relationships.filter(r => !relevantRels.includes(r));
      if (otherRels.length > 0) {
        const otherPairs = otherRels.map(r => `${_resolveCharName(r.char1, chars)}↔${_resolveCharName(r.char2, chars)}`).join(", ");
        relParts.push(`(Other relationships not in scene: ${otherPairs})`);
      }
    }

     return relParts;
  },

  // ─── _sectionWorld (extracted from buildFullContext; shared ctx bag) ───
  _sectionWorld(ctx) {
    const { project, currentChNum, sceneType, relevantWorldIds, budgetWorld } = ctx;
    // --- Section 4: World-building (relevance-sorted, scope-aware) --- C1-C12
    const worldParts = [];
    if (project.worldBuilding?.length) {
      // C2: Filter out entries not yet introduced
      const visibleEntries = project.worldBuilding.filter(w => {
        if (w.introducedInChapter > 0 && currentChNum < w.introducedInChapter) return false;
        return true;
      });
      const relevant = visibleEntries.filter(w => relevantWorldIds.has(w.id));
      const others = visibleEntries.filter(w => !relevantWorldIds.has(w.id));

      if (relevant.length || others.length) {
        worldParts.push(`\n<world_building>`);
        // C6: Sort relevant entries by scene-type relevance
        const sortBySceneRelevance = (entries) => {
          if (!sceneType) return entries;
          const categoryPriority = {
            action: ["Magic System", "Technology", "Location", "Organization"],
            dialogue: ["Culture", "Organization", "Language", "Location"],
            intimate: ["Location", "Culture", "Religion"],
            emotional: ["Culture", "Location", "History", "Religion"],
            tension: ["Location", "Organization", "Rule / Law", "Magic System"],
            revelation: ["History", "Organization", "Religion", "Culture"],
          };
          const priorities = categoryPriority[sceneType] || [];
          return [...entries].sort((a, b) => {
            const ai = priorities.indexOf(a.category);
            const bi = priorities.indexOf(b.category);
            return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
          });
        };

        // C3: Full entries for relevant, but with smart truncation for long descriptions
        for (const w of sortBySceneRelevance(relevant)) {
          // C12: Type prefix for disambiguation
          const typePrefix = w.category ? `[${w.category}] ` : "";
          let entry = `★ ${typePrefix}${w.name}`;
          // C3: Smart truncation — use first 3 sentences or 300 chars, whichever is more
          if (w.description) {
            if (w.description.length > 300) {
              entry += `: ${_truncateAtBoundary(w.description, 1000)}`;
            } else {
              entry += `: ${w.description}`;
            }
          }
          // Include category-specific details for relevant entries
          if (w.category === "Location" || !w.category) {
            if (w.geoPin && w.geoPin.label) entry += ` | Real-world basis: ${_truncateAtBoundary(w.geoPin.label, 120)}`;
            if (w.atmosphere) entry += ` | Atmosphere: ${w.atmosphere}`;
            if (w.sensoryDetails) entry += ` | Sensory: ${_truncateAtBoundary(w.sensoryDetails, 200)}`;
            if (w.dangers) entry += ` | Dangers: ${w.dangers}`;
            if (w.rules) entry += ` | Rules: ${w.rules}`;
            if (w.subLocations) entry += ` | Areas: ${w.subLocations}`;
            if (w.population) entry += ` | Population: ${w.population}`;
            if (w.resources) entry += ` | Resources: ${w.resources}`;
          } else if (w.category === "Rule / Law") {
            if (w.enforcement) entry += ` | Enforcement: ${w.enforcement}`;
            if (w.scope) entry += ` | Scope: ${w.scope}`;
            if (w.loopholes) entry += ` | Exceptions: ${w.loopholes}`;
            if (w.publicOpinion) entry += ` | Opinion: ${w.publicOpinion}`;
          } else if (w.category === "Culture") {
            if (w.values) entry += ` | Values: ${_truncateAtBoundary(w.values, 200)}`;
            if (w.customs) entry += ` | Customs: ${_truncateAtBoundary(w.customs, 200)}`;
            if (w.taboos) entry += ` | Taboos: ${w.taboos}`;
            if (w.socialHierarchy) entry += ` | Hierarchy: ${w.socialHierarchy}`;
          } else if (w.category === "Magic System") {
            if (w.magicSource) entry += ` | Source: ${w.magicSource}`;
            if (w.magicRules) entry += ` | Rules: ${_truncateAtBoundary(w.magicRules, 200)}`;
            if (w.magicCost) entry += ` | Cost: ${w.magicCost}`;
            if (w.magicRarity) entry += ` | Rarity: ${w.magicRarity}`;
            if (w.magicTypes) entry += ` | Types: ${w.magicTypes}`;
          } else if (w.category === "Technology") {
            if (w.techFunction) entry += ` | Function: ${w.techFunction}`;
            if (w.techMechanism) entry += ` | Mechanism: ${_truncateAtBoundary(w.techMechanism, 200)}`;
            if (w.techLimitations) entry += ` | Limitations: ${w.techLimitations}`;
            if (w.techAvailability) entry += ` | Availability: ${w.techAvailability}`;
          } else if (w.category === "History") {
            if (w.historyDate) entry += ` | When: ${w.historyDate}`;
            if (w.historyFigures) entry += ` | Figures: ${w.historyFigures}`;
            if (w.historyConsequences) entry += ` | Consequences: ${w.historyConsequences}`;
            if (w.historyLegacy) entry += ` | Legacy: ${w.historyLegacy}`;
          } else if (w.category === "Flora / Fauna") {
            if (w.habitat) entry += ` | Habitat: ${w.habitat}`;
            if (w.floraAppearance) entry += ` | Appearance: ${w.floraAppearance}`;
            if (w.behavior) entry += ` | Behavior: ${w.behavior}`;
            if (w.floraUses) entry += ` | Uses/Dangers: ${w.floraUses}`;
          } else if (w.category === "Language") {
            if (w.langSpeakers) entry += ` | Speakers: ${w.langSpeakers}`;
            if (w.langWriting) entry += ` | Writing: ${w.langWriting}`;
            if (w.langPhrases) entry += ` | Phrases: ${_truncateAtBoundary(w.langPhrases, 200)}`;
          } else if (w.category === "Religion") {
            if (w.deities) entry += ` | Deities: ${w.deities}`;
            if (w.coreBeliefs) entry += ` | Beliefs: ${_truncateAtBoundary(w.coreBeliefs, 200)}`;
            if (w.rituals) entry += ` | Rituals: ${w.rituals}`;
            if (w.clergy) entry += ` | Clergy: ${w.clergy}`;
          }
          // Common fields
          if (w.culturalNorms) entry += ` | Connections: ${_truncateAtBoundary(w.culturalNorms, 150)}`;
          if (w.history && !w.category?.startsWith("History")) entry += ` | Origin: ${_truncateAtBoundary(w.history, 150)}`;
          // Org hierarchy summary for organizations
          if (w.category === "Organization" && Array.isArray(w.orgHierarchy) && w.orgHierarchy.length > 0) {
            const hierStr = w.orgHierarchy.map(pos => {
              let h = pos.name || "?";
              if (pos.charId) {
                const ch = (project.characters || []).find(c => c.id === pos.charId);
                if (ch) h += ` (${ch.name})`;
              }
              return h;
            }).join(", ");
            entry += ` | Hierarchy: ${hierStr}`;
          }
          // Characters at this location
          if (Array.isArray(w.frequentCharacters) && w.frequentCharacters.length > 0) {
            const charNames = w.frequentCharacters.map(cid => {
              const ch = (project.characters || []).find(c => c.id === cid);
              return ch?.name;
            }).filter(Boolean);
            if (charNames.length) entry += ` | Characters here: ${charNames.join(", ")}`;
          }
          if (ctx.tokensUsed + this._estimateLen(entry) < budgetWorld) {
            worldParts.push(entry);
            ctx.tokensUsed += this._estimateLen(entry);
          }
        }
        // C5: Compact entries for non-scene world items — category + key field
        if (others.length) {
          for (const w of others) {
            const typePrefix = w.category ? `[${w.category}] ` : "";
            let e = `• ${typePrefix}${w.name}`;
            if (w.description) e += `: ${_truncateAtBoundary(w.description, 120)}`;
            // Add ONE key field per category for context
            if (w.category === "Magic System" && w.magicRules) e += ` (rules: ${_truncateAtBoundary(w.magicRules, 80)})`;
            else if (w.category === "Religion" && w.coreBeliefs) e += ` (beliefs: ${_truncateAtBoundary(w.coreBeliefs, 80)})`;
            else if (w.category === "Technology" && w.techFunction) e += ` (${_truncateAtBoundary(w.techFunction, 80)})`;
            else if (w.category === "Rule / Law" && w.enforcement) e += ` (enforced: ${_truncateAtBoundary(w.enforcement, 80)})`;
            else if ((w.category === "Location" || !w.category) && w.atmosphere) e += ` (${w.atmosphere})`;
            if (ctx.tokensUsed + this._estimateLen(e) < budgetWorld) {
              worldParts.push(e);
              ctx.tokensUsed += this._estimateLen(e);
            }
          }
        }
        worldParts.push(`</world_building>`);
      }
    }

     return worldParts;
  },

  // ─── _sectionPlot (extracted from buildFullContext; shared ctx bag) ───
  _sectionPlot(ctx) {
    const { project, opts, currentChNum, _charOrgCtx, budgetPlot } = ctx;
    // --- Section 5: Plot outline (mark current, hide distant future details) --- D4 partial
    const plotParts = [];
    if (project.plotOutline?.length) {
      plotParts.push(`\n<plot_outline>`);
      // D8: Sort by chapter number
      const sorted = [...project.plotOutline].sort((a, b) => (a.chapter || 0) - (b.chapter || 0));
      sorted.forEach((pl, i) => {
        const chNum = pl.chapter || i + 1;
        const isCurrent = chNum === currentChNum;
        const isNearby = Math.abs(chNum - currentChNum) <= 2;
        // D4: For distant future chapters (>3 ahead), only show titles (no summaries/beats)
        const isFarFuture = chNum > currentChNum + 3;
        // Skip very distant future chapters (>5 ahead) entirely to save tokens
        if (chNum > currentChNum + 5) return;
        let prefix = isCurrent ? "[CURRENT] " : isNearby ? "  " : "    ";
        let line = `${prefix}Ch${chNum || 1}: ${pl.title || "Untitled"}`;
        if (pl.pov || pl.date) {
          const povDateParts = [];
          if (pl.pov) povDateParts.push(`POV: ${pl.pov}`);
          if (pl.date) povDateParts.push(`scene is taking place at ${pl.date}`);
          line += ` (${povDateParts.join(", ")})`;
        }
        if (!isFarFuture) {
          if (pl.summary) line += ` — ${pl.summary}`;
          // D1: Include beats for recent past chapters too (not just current/future)
          if (pl.beats && (isCurrent || isNearby)) {
            const beats = Array.isArray(pl.beats) ? pl.beats : [];
            if (beats.length > 0) {
              // Hide future beats when cursor is inside a beat
              const visibleBeats = (isCurrent && opts.activeBeatId)
                ? beats.filter(b => {
                    const idx = beats.findIndex(x => x.id === b.id);
                    const activeIdx = beats.findIndex(x => x.id === opts.activeBeatId);
                    return idx <= activeIdx;
                  })
                : beats;

              if (visibleBeats.length > 0) {
                const beatsStr = visibleBeats.map((b, i) => {
                  const text = `${b.title || `Beat ${i+1}`}: ${b.description || ""}`;
                  if (isCurrent && opts.activeBeatId && b.id === opts.activeBeatId) {
                    return `◀ YOU ARE HERE ${text}`;
                  }
                  return text;
                }).join("; ");
                line += ` | Beats: ${beatsStr}`;
                if (isCurrent && !visibleBeats.some(b => b.id === opts.activeBeatId)) {
                  line += ` | ◀ YOU ARE HERE`;
                }
              }
            }
          }
		}
        if (pl.sceneType) line += ` [${pl.sceneType}]`;
        // Include plot-selected locations
        if (Array.isArray(pl.locations) && pl.locations.length > 0 && !isFarFuture) {
          const locNames = pl.locations.map(lid => {
            const loc = (project.worldBuilding || []).find(w => w.id === lid);
            return loc?.name;
          }).filter(Boolean);
          if (locNames.length) line += ` | Location: ${locNames.join(", ")}`;
        }
        // Include plot-selected characters for current/nearby
        if (Array.isArray(pl.characters) && pl.characters.length > 0 && (isCurrent || isNearby) && !isFarFuture) {
          const charDescs = pl.characters.map(cid => {
            const ch = (project.characters || []).find(c => c.id === cid);
            if (!ch) return null;
            let desc = ch.name;
            // Append org rank if they hold one
            if (_charOrgCtx[cid] && _charOrgCtx[cid].length > 0) {
              desc += ` [${_charOrgCtx[cid].map(o => `${o.position}, ${o.org}`).join("; ")}]`;
            }
            return desc;
          }).filter(Boolean);
          if (charDescs.length) line += ` | Characters: ${charDescs.join(", ")}`;
        }
        // For current chapter: if location has an org, note the org context
        if (isCurrent && Array.isArray(pl.locations) && pl.locations.length > 0) {
          pl.locations.forEach(lid => {
            const loc = (project.worldBuilding || []).find(w => w.id === lid);
            if (!loc) return;
            // Check if any connected world entries are organizations
            if (Array.isArray(loc.connectedTo)) {
              loc.connectedTo.forEach(connId => {
                const conn = (project.worldBuilding || []).find(w => w.id === connId);
                if (conn?.category === "Organization" && conn.orgPurpose) {
                  line += ` | Org at location: ${conn.name} (${_truncateAtBoundary(conn.orgPurpose, 80)})`;
                }
              });
            }
          });
        }
        if (ctx.tokensUsed + this._estimateLen(line) < budgetPlot) {
          plotParts.push(line);
          ctx.tokensUsed += this._estimateLen(line);
        }
      });
      plotParts.push(`</plot_outline>`);
    }
     return plotParts;
  },

  // Fix #2, #3, #4: Improved chapter context with adaptive lookback and head+tail extraction
  // REWRITTEN: buildChapterContext — D1/D5/E2-E16
  buildChapterContext(project, currentChapterIdx, opts = {}) {
    if (!project?.chapters?.length) return "";
    const parts = [];
    const totalChapters = project.chapters.length;
    const currentChNum = this._chapterNum(project, currentChapterIdx);
    // E4: Track cumulative budget for all chapter history
    const historyBudget = opts.historyBudget || 3000; // chars for prior chapters
    let historyUsed = 0;

    // E5: Adaptive lookback window based on total chapter count
    const lookbackWindow = Math.max(3, Math.min(8, Math.ceil(totalChapters * 0.3)));

    let hasHistory = false;
    for (let i = 0; i < currentChapterIdx; i++) {
      const ch = project.chapters[i];
      const chNum = this._chapterNum(project, i);
      const distance = currentChNum - chNum;
      const isRecent = distance <= lookbackWindow;

      if (ch.summary) {
        if (!hasHistory) { parts.push(`\n<chapter_history>`); hasHistory = true; }
        // E1: Detect stale summaries — warn if content changed after summary
        const summaryLen = ch.summary.length;
        const contentLen = ch.content ? ch.content.length : 0;
        // Heuristic: if content is much longer than summary suggests, it may have been rewritten
        const staleHint = (contentLen > 0 && summaryLen < 20) ? " [⚠ possibly stale — very short summary]" : "";
        // E8: Use chapter title as subtitle if title is generic
        const titleDisplay = /^Chapter\s+\d+$/i.test(ch.title || "") && ch.summary
          ? `${ch.title} — ${ch.summary.split(/[.!?]/)[0]?.trim() || ch.title}`
          : ch.title || "Untitled";
        const summaryLine = `Ch${chNum || 1} "${titleDisplay}" summary: ${ch.summary}${staleHint}`;
        if (historyUsed + summaryLine.length < historyBudget) {
          parts.push(summaryLine);
          historyUsed += summaryLine.length;
        }
      } else if (ch.content && isRecent) {
        const plain = _htmlToPlain(ch.content);
        if (plain) {
          if (!hasHistory) { parts.push(`\n<chapter_history>`); hasHistory = true; }
          // E9: Increased head+tail budget for unsummarized recent chapters
          if (plain.length <= 2000) {
            const entry = `Ch${chNum || 1} "${ch.title}" (full): ${plain}`;
            if (historyUsed + entry.length < historyBudget) {
              parts.push(entry); historyUsed += entry.length;
            }
          } else {
            const head = _sliceHeadAtBoundary(plain, 600);
            const tail = _sliceAtBoundary(plain, 1000);
            const entry1 = `Ch${chNum || 1} "${ch.title}" (opening): ${head}`;
            const entry2 = `Ch${chNum || 1} "${ch.title}" (tail): ...${tail}`;
            if (historyUsed + entry1.length + entry2.length < historyBudget) {
              parts.push(entry1); parts.push(entry2);
              historyUsed += entry1.length + entry2.length;
            }
          }
        }
      } else if (ch.content && !isRecent) {
        // E3: Emergency micro-summary for old unsummarized chapters — extract first 2 sentences
        const plain = _htmlToPlain(ch.content);
        const wc = wordCount(ch.content);
        if (wc > 0) {
          if (!hasHistory) { parts.push(`\n<chapter_history>`); hasHistory = true; }
          const microSummary = _sliceHeadAtBoundary(plain, 200);
          const entry = `Ch${chNum || 1} "${ch.title}": ${microSummary}... [${wc} words total, unsummarized]`;
          if (historyUsed + entry.length < historyBudget) {
            parts.push(entry); historyUsed += entry.length;
          }
        }
      }
    }
    if (hasHistory) parts.push(`</chapter_history>`);

    // E10: Include tail of immediately previous chapter for transition continuity
    if (currentChapterIdx > 0) {
      const prevCh = project.chapters[currentChapterIdx - 1];
      if (prevCh?.content) {
        const prevPlain = _htmlToPlain(prevCh.content);
        if (prevPlain && prevPlain.length > 100) {
          const prevTail = _sliceAtBoundary(prevPlain, 400);
          parts.push(`\n<previous_chapter_ending chapter="${currentChapterIdx}" title="${prevCh.title || ''}">\n...${prevTail}\n</previous_chapter_ending>`);
        }
      }
    }

    // E2/E12: Current chapter — head + middle sample + tail strategy with semantic formatting
    const cur = project.chapters[currentChapterIdx];
    if (cur?.content) {
      // E12: Preserve semantic markers when converting HTML
      let plain = cur.content;
      // Convert semantic HTML to lightweight markers before stripping
      plain = plain.replace(/<hr[^>]*>/gi, '\n---\n');
      plain = plain.replace(/<em>([^<]*)<\/em>/gi, '*$1*');
      plain = plain.replace(/<strong>([^<]*)<\/strong>/gi, '**$1**');
      plain = plain.replace(/<[^>]*>/g, ' ').replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
        .replace(/&quot;/g, '"').replace(/&#\d+;/g, ' ').replace(/&[a-z]+;/gi, ' ')
        .replace(/\s+/g, ' ').trim();

      if (plain) {
        let chHeader = `\n<current_chapter number="${currentChNum}" title="${cur.title || ''}"`;
        if (cur.pov) chHeader += ` pov="${cur.pov}"`;
        // E16: Include scene notes awareness in chapter context header
        if (cur.sceneNotes) chHeader += ` scene_direction="true"`;
        chHeader += `>`;
        parts.push(chHeader);

        const maxCurrentChapter = opts.currentChapterBudget || 4000;
        if (plain.length <= maxCurrentChapter) {
          parts.push(plain);
        } else {
          // E2: Three-part strategy — head + middle sample + tail
          const headSize = Math.floor(maxCurrentChapter * 0.2);
          const midSize = Math.floor(maxCurrentChapter * 0.15);
          const tailSize = Math.floor(maxCurrentChapter * 0.65);
          const head = _sliceHeadAtBoundary(plain, headSize);
          // Middle sample: centered at ~45% of the chapter
          const midStart = Math.floor(plain.length * 0.4);
          const midSlice = plain.slice(midStart, midStart + midSize + 200);
          const midClean = _sliceHeadAtBoundary(midSlice, midSize);
          const tail = _sliceAtBoundary(plain, tailSize);
          const omittedWords = Math.round((plain.length - headSize - midSize - tailSize) / 5);
          parts.push(head);
          parts.push(`\n[... ${omittedWords} words omitted ...]\n`);
          parts.push(`...${midClean}...`);
          parts.push(`\n[... continuing ...]\n`);
          parts.push(`...${tail}`);
        }
        parts.push(`</current_chapter>`);
      }
    }

    // D5: REMOVED the separate <upcoming_planned> section — it duplicated the plot outline
    // in buildFullContext. The plot outline section already includes nearby chapters.

    return parts.join("\n");
  },

  buildSceneContext(sceneNotes) {
    return sceneNotes ? `<scene_direction>\n${sceneNotes}\n</scene_direction>` : "";
  },

  // REWRITTEN: Mode-specific context assembly — E11/E16/F3/F6/F8/F9/D6/I3
  buildForMode(project, chapterIdx, sceneNotes, mode, selectedText, contextWindow, opts = {}) {
    const sections = [];

    // I3: Scale budgets based on model context window
    // Default budgets are tuned for ~128k models. Scale down for smaller models.
    const ctxK = (contextWindow || 128000) / 1000;
    const scale = ctxK >= 128 ? 1.0 : ctxK >= 32 ? 0.8 : ctxK >= 16 ? 0.5 : 0.35;

    // D6: Detect scene type from plot for context modulation
    const curPlotEntry = (project.plotOutline || []).find(pl => (pl.chapter || 0) === this._chapterNum(project, chapterIdx));
    const sceneType = curPlotEntry?.sceneType || "";

    switch (mode) {
      case "summarize": {
        sections.push(this.buildFullContext(project, chapterIdx, { tokenBudget: Math.round(30000 * scale), activeBeatId: opts.activeBeatId }));
        sections.push(this.buildChapterContext(project, chapterIdx, { currentChapterBudget: Math.round(60000 * scale), historyBudget: Math.round(15000 * scale) }));
        break;
      }
      case "brainstorm": {
        sections.push(this.buildFullContext(project, chapterIdx, { tokenBudget: Math.round(45000 * scale), activeBeatId: opts.activeBeatId }));
        sections.push(this.buildChapterContext(project, chapterIdx, { currentChapterBudget: Math.round(40000 * scale), historyBudget: Math.round(20000 * scale) }));
        if (sceneNotes) sections.push(this.buildSceneContext(sceneNotes));
        break;
      }
      case "scene": {
        sections.push(this.buildFullContext(project, chapterIdx, { tokenBudget: Math.round(50000 * scale), activeBeatId: opts.activeBeatId }));
        sections.push(this.buildChapterContext(project, chapterIdx, { currentChapterBudget: Math.round(30000 * scale), historyBudget: Math.round(20000 * scale) }));
        if (sceneNotes) sections.push(this.buildSceneContext(sceneNotes));
        break;
      }
      case "dialogue": {
        sections.push(this.buildFullContext(project, chapterIdx, { tokenBudget: Math.round(55000 * scale), activeBeatId: opts.activeBeatId }));
        sections.push(this.buildChapterContext(project, chapterIdx, { currentChapterBudget: Math.round(30000 * scale), historyBudget: Math.round(15000 * scale) }));
        if (sceneNotes) sections.push(this.buildSceneContext(sceneNotes));
        break;
      }
      case "continue": {
        sections.push(this.buildFullContext(project, chapterIdx, { tokenBudget: Math.round(40000 * scale), activeBeatId: opts.activeBeatId }));
        sections.push(this.buildChapterContext(project, chapterIdx, { currentChapterBudget: Math.round(50000 * scale), historyBudget: Math.round(20000 * scale) }));
        if (sceneNotes) sections.push(this.buildSceneContext(sceneNotes));
        break;
      }
      case "rewrite": {
        sections.push(this.buildFullContext(project, chapterIdx, { tokenBudget: Math.round(35000 * scale), activeBeatId: opts.activeBeatId }));
        sections.push(this.buildChapterContext(project, chapterIdx, { currentChapterBudget: Math.round(35000 * scale), historyBudget: Math.round(15000 * scale) }));
        if (selectedText && project.chapters?.[chapterIdx]?.content) {
          const plain = _htmlToPlain(project.chapters[chapterIdx].content);
          // FIX 2.7: Multi-strategy position detection — use longer substring, try multiple positions
          let selIdx = -1;
          // Strategy 1: Match first 150 chars (much more unique than 50)
          const matchLen = Math.min(selectedText.length, 150);
          selIdx = plain.indexOf(selectedText.slice(0, matchLen));
          // Strategy 2: If first occurrence doesn't match length, try finding the LAST occurrence
          // (user likely selected near the end of the chapter where they're actively writing)
          if (selIdx === -1) {
            selIdx = plain.lastIndexOf(selectedText.slice(0, Math.min(selectedText.length, 80)));
          }
          // Strategy 3: Normalize whitespace and try again
          if (selIdx === -1) {
            const normPlain = plain.replace(/\s+/g, ' ');
            const normSel = selectedText.replace(/\s+/g, ' ').slice(0, 100);
            const normIdx = normPlain.indexOf(normSel);
            if (normIdx >= 0) selIdx = normIdx;
          }
          if (selIdx >= 0) {
            const beforeStart = Math.max(0, selIdx - 500);
            const afterEnd = Math.min(plain.length, selIdx + selectedText.length + 500);
            const surroundingBefore = plain.slice(beforeStart, selIdx).trim();
            const surroundingAfter = plain.slice(selIdx + selectedText.length, afterEnd).trim();
            if (surroundingBefore || surroundingAfter) {
              let ctx = `\n<rewrite_surrounding_context>`;
              if (surroundingBefore) ctx += `\n[Text before selection]: ...${surroundingBefore}`;
              ctx += `\n[SELECTED TEXT TO REWRITE]: ${selectedText || ""}`;
              if (surroundingAfter) ctx += `\n[Text after selection]: ${surroundingAfter}...`;
              ctx += `\n</rewrite_surrounding_context>`;
              sections.push(ctx);
            }
          }
        }
        break;
      }
      default: {
        console.warn(`[ContextEngine] Unknown mode "${mode}", using minimal context`);
        sections.push(this.buildMinimalContext(project, chapterIdx));
        sections.push(this.buildChapterContext(project, chapterIdx));
      }
    }

    return sections.filter(s => s && s.trim()).join("\n\n");
  },

  // REWRITTEN: Tab-specific context with much richer information
  // Fixes: G1-G10, B9, B16, C9
  buildTabContext(project, chapterIdx, tabName, editingEntity) {
	const currentChNum = this._chapterNum(project, chapterIdx);
    if (!project) return "";
    const parts = [];

    // G1: Use medium-weight context instead of minimal — include synopsis, themes, and key metadata
    const pov = this._effectivePov(project, chapterIdx);
    parts.push(`<novel title="${project.title}">`);
    if (project.genre) parts.push(`Genre: ${project.genre}`);
    if (project.tone) parts.push(`Tone: ${project.tone}`);
    if (pov) parts.push(`POV: ${pov}`);
    if (project.themes) parts.push(`Themes: ${project.themes}`);
    if (project.heatLevel != null) parts.push(`Heat: ${project.heatLevel}/5`);
    if (project.synopsis) parts.push(`Synopsis: ${project.synopsis}`);
    // G10: Include continuity notes
    if (project.continuityNotes) parts.push(`Continuity notes: ${project.continuityNotes}`);
    // G7: Include current chapter info
    const curChapter = project.chapters?.[chapterIdx];
    parts.push(`\nCurrently writing: Chapter ${currentChNum}${curChapter?.title ? ` "${curChapter.title}"` : ""} (${project.chapters?.length || 0} chapters total)`);
    if (curChapter?.summary) parts.push(`Current chapter summary: ${curChapter.summary}`);
    parts.push(`</novel>`);

    // Tab-specific context injection
    switch (tabName) {
      case "characters": {
        if (editingEntity && project.characters?.length) {
          const editing = project.characters.find(c => c.id === editingEntity);
          if (editing) {
            parts.push(`\n<currently_editing_character>`);
            // G5: Explicitly label which fields are empty vs filled
            const isBulkEditing = editing.isBulk;
            const fields = isBulkEditing
              ? [["name","Group Name"],["role","Role"],["bulkCount","Count"],["bulkDescription","Description"],["appearance","Appearance/Uniform"],["habits","Behavior/Culture"],["allegiances","Allegiances"],["tags","Tags"],["desires","Story Purpose"],["strengths","Strengths/Resources"],["flaws","Weaknesses"],["canonNotes","Notable Members"],["notes","Author Notes"]]
              : [["name","Name"],["role","Role"],["gender","Gender"],["age","Age"],["pronouns","Pronouns"],["orientation","Orientation"],["aliases","Aliases"],["occupation","Occupation"],["height","Height"],["build","Build"],["tags","Tags"],["allegiances","Allegiances"],["appearance","Appearance"],["personality","Personality"],["backstory","Backstory"],["desires","Desires"],["shortTermGoals","Short-term goals"],["longTermGoals","Long-term goals"],["speechPattern","Speech pattern"],["voiceSamples","Voice samples"],["habits","Habits & mannerisms"],["fears","Fears"],["flaws","Flaws"],["strengths","Strengths"],["skills","Skills"],["internalConflict","Internal conflict"],["externalConflict","External conflict"],["signatureItems","Signature items"],["secrets","Known secrets"],["hiddenSecrets","Hidden secrets"],["kinks","Preferences"],["arc","Arc"],["canonNotes","Canon notes"],["currentEmotionalState","Current emotional state"],["obligationsOwed","Obligations owed"],["knowledgeState","Knowledge state"],["notes","Author notes"]];
            if (isBulkEditing) {
              parts.push(`  [BULK CHARACTER GROUP: ${editing.bulkCount || "many"} individuals — treat as a collective, not individuals]`);
              if (editing.bulkDescription) parts.push(`  Group description: ${editing.bulkDescription}`);
            }
            const emptyFields = [];
            const filledFields = [];
            fields.forEach(([k, label]) => {
              if (editing[k]) {
                filledFields.push(`  ${label}: ${editing[k]}`);
              } else {
                emptyFields.push(label);
              }
            });
            filledFields.forEach(f => parts.push(f));
            if (emptyFields.length) parts.push(`  [Empty fields needing content: ${emptyFields.join(", ")}]`);
            // ─── CROSS-REFERENCE DATA for this character ───
            const crossRefCtx = _buildCrossRefContext(project, editingEntity);
            if (crossRefCtx) parts.push(`\n<cross_references>\n${crossRefCtx}\n</cross_references>`);
            parts.push(`</currently_editing_character>`);
          }
          // Other characters with personality for consistency checking
          const others = project.characters.filter(c => c.id !== editingEntity);
          if (others.length) {
            parts.push(`\nOther characters:`);
            others.forEach(c => {
              let line = `  • ${c.name} (${c.role})`;
              if (c.isBulk) line += ` [BULK GROUP × ${c.bulkCount || "many"}]`;
              if (c.personality) line += ` — ${_truncateAtBoundary(c.personality, 1000)}`;
              parts.push(line);
            });
          }
        } else if (project.characters?.length) {
          parts.push(`\nExisting characters:`);
          project.characters.forEach(c => {
            let line = `  • ${c.name} (${c.role})`;
            if (c.isBulk) line += ` [BULK GROUP × ${c.bulkCount || "many"}]`;
            if (c.personality) line += ` — ${_truncateAtBoundary(c.personality, 1000)}`;
            parts.push(line);
          });
        }
        // Include relationships for character consistency
        if (project.relationships?.length) {
          const chars = project.characters || [];
          parts.push(`\nRelationships: ${project.relationships.map(r => `${_resolveCharName(r.char1, chars)} ↔ ${_resolveCharName(r.char2, chars)}: ${r.dynamic} [${r.status}]`).join("; ")}`);
        }
        // ─── Organization Context for Characters ───
        const orgEntries = (project.worldBuilding || []).filter(w => w.category === "Organization");
        if (orgEntries.length > 0) {
          parts.push(`\n<organizations>`);
          orgEntries.forEach(org => {
            parts.push(`${org.name}${org.orgPurpose ? ` — ${org.orgPurpose}` : ""}`);
            if (Array.isArray(org.orgHierarchy) && org.orgHierarchy.length > 0) {
              org.orgHierarchy.forEach(pos => {
                const heldBy = pos.charId ? (project.characters || []).find(c => c.id === pos.charId) : null;
                const reportsTo = pos.parentId ? org.orgHierarchy.find(p => p.id === pos.parentId) : null;
                const reportsToChar = reportsTo?.charId ? (project.characters || []).find(c => c.id === reportsTo.charId) : null;
                let line = `  • ${pos.name || "Unnamed position"}${pos.role ? ` (${pos.role})` : ""}`;
                if (heldBy) line += ` — held by ${heldBy.name} (${heldBy.role})`;
                else line += ` — VACANT (fill this position)`;
                if (reportsTo) line += ` → reports to ${reportsToChar?.name || reportsTo.name || "Unknown"}`;
                parts.push(line);
              });
            }
          });
          parts.push(`</organizations>`);
        }
        // ─── Location Context for Characters (so AI can link occupations to specific locations) ───
        const locationEntries = (project.worldBuilding || []).filter(w => w.category === "Location" && w.name);
        if (locationEntries.length > 0) {
          parts.push(`\n<locations>`);
          locationEntries.forEach(loc => {
            let line = `  • ${loc.name}`;
            if (loc.description) line += `: ${_truncateAtBoundary(loc.description, 150)}`;
            parts.push(line);
          });
          parts.push(`  [When creating a character, if their occupation or backstory ties to one of these locations, reference it by name in backstory/canonNotes/allegiances.]`);
          parts.push(`</locations>`);
        }
        break;
      }
      case "world": {
        // C9: Include descriptions for existing world entries
        if (project.worldBuilding?.length) {
          parts.push(`\n<existing_world_entries>`);
          project.worldBuilding.forEach(w => {
            let line = `• ${w.name}`;
            if (w.category) line += ` [${w.category}]`;
            if (w.description) line += `: ${_truncateAtBoundary(w.description, 1000)}`;
            if (w.history) line += ` | History: ${_truncateAtBoundary(w.history, 200)}`;
            if (w.culturalNorms) line += ` | Connections: ${_truncateAtBoundary(w.culturalNorms, 200)}`;
            // Category-specific fields
            if (w.category === "Location" || !w.category) {
              if (w.atmosphere) line += ` | Atmosphere: ${w.atmosphere}`;
              if (w.sensoryDetails) line += ` | Sensory: ${_truncateAtBoundary(w.sensoryDetails, 200)}`;
              if (w.subLocations) line += ` | Sub-locations: ${w.subLocations}`;
              if (w.dangers) line += ` | Dangers: ${w.dangers}`;
              if (w.rules) line += ` | Rules: ${w.rules}`;
              if (w.resources) line += ` | Resources: ${w.resources}`;
              if (w.population) line += ` | Population: ${w.population}`;
            } else if (w.category === "Rule / Law") {
              if (w.enforcement) line += ` | Enforcement: ${w.enforcement}`;
              if (w.scope) line += ` | Scope: ${w.scope}`;
              if (w.loopholes) line += ` | Exceptions: ${w.loopholes}`;
              if (w.publicOpinion) line += ` | Opinion: ${w.publicOpinion}`;
            } else if (w.category === "Culture") {
              if (w.values) line += ` | Values: ${_truncateAtBoundary(w.values, 200)}`;
              if (w.customs) line += ` | Customs: ${_truncateAtBoundary(w.customs, 200)}`;
              if (w.taboos) line += ` | Taboos: ${w.taboos}`;
              if (w.socialHierarchy) line += ` | Social hierarchy: ${w.socialHierarchy}`;
            } else if (w.category === "Magic System") {
              if (w.magicSource) line += ` | Source: ${w.magicSource}`;
              if (w.magicRules) line += ` | Rules: ${_truncateAtBoundary(w.magicRules, 200)}`;
              if (w.magicCost) line += ` | Cost: ${w.magicCost}`;
              if (w.magicTypes) line += ` | Types: ${w.magicTypes}`;
            } else if (w.category === "Technology") {
              if (w.techFunction) line += ` | Function: ${w.techFunction}`;
              if (w.techMechanism) line += ` | Mechanism: ${_truncateAtBoundary(w.techMechanism, 200)}`;
              if (w.techLimitations) line += ` | Limitations: ${w.techLimitations}`;
            } else if (w.category === "History") {
              if (w.historyDate) line += ` | When: ${w.historyDate}`;
              if (w.historyFigures) line += ` | Figures: ${w.historyFigures}`;
              if (w.historyConsequences) line += ` | Consequences: ${w.historyConsequences}`;
            } else if (w.category === "Flora / Fauna") {
              if (w.habitat) line += ` | Habitat: ${w.habitat}`;
              if (w.floraAppearance) line += ` | Appearance: ${w.floraAppearance}`;
              if (w.behavior) line += ` | Behavior: ${w.behavior}`;
              if (w.floraUses) line += ` | Uses: ${w.floraUses}`;
            } else if (w.category === "Language") {
              if (w.langSpeakers) line += ` | Speakers: ${w.langSpeakers}`;
              if (w.langWriting) line += ` | Writing: ${w.langWriting}`;
              if (w.langPhrases) line += ` | Phrases: ${_truncateAtBoundary(w.langPhrases, 200)}`;
            } else if (w.category === "Religion") {
              if (w.deities) line += ` | Deities: ${w.deities}`;
              if (w.coreBeliefs) line += ` | Beliefs: ${_truncateAtBoundary(w.coreBeliefs, 200)}`;
              if (w.rituals) line += ` | Rituals: ${w.rituals}`;
            }
            // Organization-specific: only surface for Organization entries
            if (w.category === "Organization") {
              if (w.orgPurpose) line += ` | Purpose: ${_truncateAtBoundary(w.orgPurpose, 200)}`;
            }
            // Include frequent characters by name
            if (Array.isArray(w.frequentCharacters) && w.frequentCharacters.length > 0 && project.characters) {
              const charNames = w.frequentCharacters.map(cid => {
                const ch = project.characters.find(c => c.id === cid);
                return ch?.name || "?";
              }).filter(n => n !== "?");
              if (charNames.length) line += ` | Characters here: ${charNames.join(", ")}`;
            }
            // Include org hierarchy summary — ONLY for Organizations
            if (w.category === "Organization" && Array.isArray(w.orgHierarchy) && w.orgHierarchy.length > 0 && project.characters) {
              const hierParts = w.orgHierarchy.map(pos => {
                let h = pos.name || "Unnamed";
                if (pos.role) h += ` (${pos.role})`;
                if (pos.charId) {
                  const ch = project.characters.find(c => c.id === pos.charId);
                  if (ch) h += ` — held by ${ch.name}`;
                }
                return h;
              });
              line += ` | Hierarchy: ${hierParts.join(" → ")}`;
            }
            // Include connected entries
            if (Array.isArray(w.connectedTo) && w.connectedTo.length > 0) {
              const connNames = w.connectedTo.map(cid => {
                const other = project.worldBuilding.find(ww => ww.id === cid);
                return other?.name || "?";
              }).filter(n => n !== "?");
              if (connNames.length) line += ` | Connected to: ${connNames.join(", ")}`;
            }
            // Include parent location (geographic nesting)
            if (w.parentLocation) {
              const parent = project.worldBuilding.find(ww => ww.id === w.parentLocation);
              if (parent?.name) line += ` | Located within: ${parent.name}`;
            }
            parts.push(line);
          });
          parts.push(`</existing_world_entries>`);
        }
        // G2: Include characters for world consistency
        // Rich character profiles for world-building consistency
        if (project.characters?.length) {
          parts.push(`\n<character_profiles>`);
          project.characters.forEach(c => {
            const cr = _deriveCrossRefs(project, c.id);
            let line = `  • ${c.name} (${c.role})`;
            if (cr.derivedOccupation) line += ` — ${cr.derivedOccupation}`;
            else if (c.occupation) line += ` — ${c.occupation}`;
            if (c.personality) line += `\n    Personality: ${_truncateAtBoundary(c.personality, 1000)}`;
            if (cr.derivedAllegiances) line += `\n    Allegiances: ${cr.derivedAllegiances}`;
            else if (c.allegiances) line += `\n    Allegiances: ${c.allegiances}`;
            if (c.skills) line += `\n    Skills: ${c.skills}`;
            if (c.arc) line += `\n    Arc: ${_truncateAtBoundary(c.arc, 1000)}`;
            if (c.status && c.status !== "alive") line += `\n    Status: ${c.status}`;
            if (cr.charOrgPositions?.length) line += `\n    Org positions: ${cr.charOrgPositions.map(o => `${o.position} in ${o.orgName}${o.reportsTo ? ` (reports to ${o.reportsTo})` : ""}${o.subordinates.length ? ` (manages: ${o.subordinates.map(s => s.name).join(", ")})` : ""}`).join("; ")}`;
            if (cr.charLocations?.length) line += `\n    Locations: ${cr.charLocations.map(l => l.name).join(", ")}`;
            if (cr.charRelationships?.length) line += `\n    Key relationships: ${cr.charRelationships.slice(0, 5).map(r => `${r.otherName} (${r.category || "romantic"}, ${r.status})`).join("; ")}`;
            parts.push(line);
          });
          parts.push(`</character_profiles>`);
        }
        break;
      }
      case "plot": {
        // If focused on a specific plot entry, highlight it first
        if (editingEntity && project.plotOutline?.length) {
          const focus = project.plotOutline.find(pl => pl.id === editingEntity);
          if (focus) {
            parts.push(`\n<currently_editing_plot_entry chapter="${focus.chapter || "?"}">`);
            if (focus.title) parts.push(`  Title: ${focus.title}`);
            if (focus.summary) parts.push(`  Summary: ${focus.summary}`);
            if (focus.pov) parts.push(`  POV: ${focus.pov}`);
            if (focus.sceneType) parts.push(`  Scene type: ${focus.sceneType}`);
            if (focus.date) parts.push(`  Story date: ${focus.date}`);
            if (focus.narrativeDistance) parts.push(`  Narrative distance: ${focus.narrativeDistance}`);
            if (focus.sensoryPalette) parts.push(`  Sensory palette: ${focus.sensoryPalette}`);
            if (focus.subtextNotes) parts.push(`  Subtext: ${focus.subtextNotes}`);
            if (typeof focus.tensionLevel === "number") parts.push(`  Tension level: ${focus.tensionLevel}/10`);
            if (focus.beats) {
              const beatsText = Array.isArray(focus.beats)
                ? focus.beats.map(b => `    - ${b.title || "Beat"}: ${b.description || ""}`).join("\n")
                : focus.beats;
              parts.push(`  Beats:\n${beatsText}`);
            }
            if (Array.isArray(focus.characters) && focus.characters.length) {
              const names = focus.characters.map(cid => {
                const ch = (project.characters || []).find(c => c.id === cid);
                return ch?.name;
              }).filter(Boolean);
              if (names.length) parts.push(`  Characters: ${names.join(", ")}`);
            }
            if (Array.isArray(focus.locations) && focus.locations.length) {
              const names = focus.locations.map(lid => {
                const loc = (project.worldBuilding || []).find(w => w.id === lid);
                return loc?.name;
              }).filter(Boolean);
              if (names.length) parts.push(`  Locations: ${names.join(", ")}`);
            }
            // List empty fields the AI should fill
            const emptyPlotFields = [];
            ["title","summary","pov","sceneType","date","narrativeDistance","sensoryPalette","subtextNotes"].forEach(k => {
              if (!focus[k]) emptyPlotFields.push(k);
            });
            if (!Array.isArray(focus.beats) || focus.beats.length === 0) emptyPlotFields.push("beats");
            if (!Array.isArray(focus.characters) || focus.characters.length === 0) emptyPlotFields.push("characters");
            if (emptyPlotFields.length) parts.push(`  [Empty fields needing content: ${emptyPlotFields.join(", ")}]`);
            parts.push(`</currently_editing_plot_entry>`);
          }
        }
        // G4: Include chapter content summary for plot-aware suggestions
        if (project.plotOutline?.length) {
          parts.push(`\n<existing_plot>`);
          project.plotOutline.forEach((pl, i) => {
            let line = `Ch${pl.chapter || i + 1}: ${pl.title || "Untitled"}`;
            if (pl.summary) line += ` — ${pl.summary}`;
            if (pl.beats) {
              const beatsText = Array.isArray(pl.beats)
                ? pl.beats.map(b => `${b.title || "Beat"}: ${b.description || ""}`).join("; ")
                : pl.beats;
              if (beatsText) line += ` | Beats: ${beatsText}`;
            }
            // Include locations
            if (Array.isArray(pl.locations) && pl.locations.length > 0) {
              const locNames = pl.locations.map(lid => {
                const loc = (project.worldBuilding || []).find(w => w.id === lid);
                return loc?.name;
              }).filter(Boolean);
              if (locNames.length) line += ` | Location: ${locNames.join(", ")}`;
            }
            // Include characters with org roles
            if (Array.isArray(pl.characters) && pl.characters.length > 0) {
              const charDescs = pl.characters.map(cid => {
                const ch = (project.characters || []).find(c => c.id === cid);
                if (!ch) return null;
                // Check if this character holds any org positions
                let desc = ch.name;
                (project.worldBuilding || []).forEach(w => {
                  if (w.category !== "Organization" || !Array.isArray(w.orgHierarchy)) return;
                  w.orgHierarchy.forEach(pos => {
                    if (pos.charId === cid) desc += ` [${pos.name}, ${w.name}]`;
                  });
                });
                return desc;
              }).filter(Boolean);
              if (charDescs.length) line += ` | Characters: ${charDescs.join(", ")}`;
            }
            // Auto-derived cross-references for this plot entry
            const plotCR = _buildPlotCrossRefContext(project, pl.id);
            if (plotCR) line += `\n  [Scene context: ${plotCR.replace(/\n/g, "; ")}]`;
            parts.push(line);
          });
          parts.push(`</existing_plot>`);
        }
        if (project.characters?.length) {
          parts.push(`\nCharacters: ${project.characters.map(c => {
            const cr = _deriveCrossRefs(project, c.id);
            let desc = `${c.name} (${c.role}`;
            if (cr.derivedOccupation) desc += `, ${cr.derivedOccupation}`;
            else if (c.occupation) desc += `, ${c.occupation}`;
            desc += `)`;
            if (c.status && c.status !== "alive") desc += ` [${c.status}]`;
            if (cr.charLocations?.length) desc += ` [at: ${cr.charLocations.map(l => l.name).join(", ")}]`;
            return desc;
          }).join("; ")}`);
        }
        // Include locations with atmosphere/dangers for plot planning
        const plotLocations = (project.worldBuilding || []).filter(w => w.name && (w.category === "Location" || !w.category));
        if (plotLocations.length > 0) {
          parts.push(`\nAvailable locations:`);
          plotLocations.forEach(l => {
            let line = `  📍 ${l.name}`;
            if (l.atmosphere) line += ` — ${l.atmosphere}`;
            if (l.dangers) line += ` | Dangers: ${l.dangers}`;
            const freqNames = (l.frequentCharacters || []).map(cid => { const ch = (project.characters || []).find(c => c.id === cid); return ch?.name; }).filter(Boolean);
            if (freqNames.length) line += ` | Characters: ${freqNames.join(", ")}`;
            parts.push(line);
          });
        }
        // Include key relationship tensions for plot planning
        if (project.relationships?.length) {
          const highTension = project.relationships.filter(r => r.tension === "high" || r.tension === "explosive");
          if (highTension.length > 0) {
            parts.push(`\nHigh-tension relationships:`);
            highTension.forEach(r => {
              const c1 = _resolveCharName(r.char1, project.characters);
              const c2 = _resolveCharName(r.char2, project.characters);
              parts.push(`  ⚡ ${c1} ↔ ${c2}: ${r.tension} (${r.category || "romantic"})${r.conflictSource ? ` — conflict: ${r.conflictSource}` : ""}`);
            });
          }
        }
        // Include organizations for plot planning
        const plotOrgs = (project.worldBuilding || []).filter(w => w.name && w.category === "Organization");
        if (plotOrgs.length > 0) {
          parts.push(`\nOrganizations: ${plotOrgs.map(o => {
            let desc = o.name;
            if (o.orgPurpose) desc += ` — ${_truncateAtBoundary(o.orgPurpose, 100)}`;
            if (Array.isArray(o.orgHierarchy) && o.orgHierarchy.length > 0) {
              const leaders = o.orgHierarchy.filter(p => !p.parentId && p.charId).map(p => {
                const ch = (project.characters || []).find(c => c.id === p.charId);
                return ch ? `${p.name}: ${ch.name}` : p.name;
              });
              if (leaders.length) desc += ` [${leaders.join(", ")}]`;
            }
            return desc;
          }).join("; ")}`);
        }
        // G4: Include chapter summaries for what's actually been written
        // FIX: Use original chapter index, not filtered index
        const writtenSummaries = [];
        (project.chapters || []).forEach((ch, i) => {
          if (ch.summary) writtenSummaries.push(`Ch${this._chapterNum(project, i)}: ${ch.summary}`);
        });
        if (writtenSummaries.length) {
          parts.push(`\n<written_chapter_summaries>`);
          writtenSummaries.forEach(s => parts.push(s));
          parts.push(`</written_chapter_summaries>`);
        }
        // D13: Include current chapter tail so AI knows where the story actually is
        const curCh = project.chapters?.[chapterIdx];
        if (curCh?.content) {
          const curPlain = _htmlToPlain(curCh.content);
          if (curPlain && curPlain.length > 50) {
            const tail = _sliceAtBoundary(curPlain, 600);
            parts.push(`\n<current_writing_position chapter="${currentChNum}" words="${wordCount(curCh.content)}">\n...${tail}\n</current_writing_position>`);
          }
        }
        // D13: Total project progress
        const totalWords = (project.chapters || []).reduce((sum, ch) => sum + wordCount(ch.content), 0);
        parts.push(`\nProject progress: ${totalWords.toLocaleString()} words across ${project.chapters?.length || 0} chapters`);
        break;
      }
      case "relationships": {
        if (project.characters?.length) {
          parts.push(`\nCharacters:`);
          project.characters.forEach(c => {
            let line = `  • ${c.name} (${c.role}`;
            // Derive occupation from org positions
            const crossRef = _deriveCrossRefs(project, c.id);
            if (crossRef.derivedOccupation) line += `, ${crossRef.derivedOccupation}`;
            else if (c.occupation) line += `, ${c.occupation}`;
            line += `)`;
            if (c.personality) line += ` — ${_truncateAtBoundary(c.personality, 1000)}`;
            if (crossRef.derivedAllegiances) line += ` [Allegiance: ${crossRef.derivedAllegiances}]`;
            else if (c.allegiances) line += ` [Allegiance: ${c.allegiances}]`;
            // Location context
            if (crossRef.charLocations?.length) line += ` [At: ${crossRef.charLocations.map(l => l.name).join(", ")}]`;
            // Status
            if (c.status && c.status !== "alive") line += ` [${c.status.toUpperCase()}]`;
            if (c.orientation) line += ` [${c.orientation}]`;
            if (c.isBulk) line += ` [BULK GROUP: ${c.bulkCount || "many"} — ${c.bulkDescription || "background"}]`;
            parts.push(line);
          });
        }
        // B9/B16: Include full relationship details — FIX 1.21/6.6: gate by meetsInChapter
        if (project.relationships?.length) {
          const chars = project.characters || [];
          const currentChNum = this._chapterNum(project, chapterIdx)
          const visibleRels = project.relationships.filter(r => !(r.meetsInChapter > 0 && currentChNum < r.meetsInChapter));
          if (visibleRels.length) {
            parts.push(`\n<existing_relationships>`);
            visibleRels.forEach(r => {
            const c1Name = _resolveCharName(r.char1, chars);
            const c2Name = _resolveCharName(r.char2, chars);
            let line = `${c1Name} ↔ ${c2Name}: ${r.dynamic} | Category: ${r.category || "romantic"} | Status: ${r.status} | Tension: ${r.tension}`;
            if (r.tensionType) line += ` (${r.tensionType})`;
            if (r.powerDynamic && r.powerDynamic !== "equal") line += ` | Power: ${r.powerDynamic}`;
            if (r.trustLevel) line += ` | Trust: ${r.trustLevel}`;
            if (r.chemistry) line += ` | Chemistry: ${_truncateAtBoundary(r.chemistry, 150)}`;
            if (r.conflictSource) line += ` | Conflict: ${_truncateAtBoundary(r.conflictSource, 150)}`;
            if (r.sharedSecrets) line += ` | Shared secrets: ${_truncateAtBoundary(r.sharedSecrets, 150)}`;
            if (r.keyScenes) line += ` | Key scenes: ${_truncateAtBoundary(r.keyScenes, 200)}`;
            if (r.terms) line += ` | Terms: ${r.terms}`;
            if (r.taboos) line += ` | Taboos: ${r.taboos}`;
            if (r.isPublic === false) line += ` | [SECRET RELATIONSHIP]`;
            if (r.progression) line += ` | Arc: ${r.progression}`;
            if (r.char1Perspective) line += ` | ${c1Name}'s view: ${r.char1Perspective}`;
            if (r.char2Perspective) line += ` | ${c2Name}'s view: ${r.char2Perspective}`;
            if (r.evolutionTimeline) line += ` | Timeline: ${r.evolutionTimeline}`;
            if (r.notes) line += ` | Notes: ${r.notes}`;
            // Auto-derived cross-references
            const relCR = _buildRelCrossRefContext(project, r.id);
            if (relCR) line += ` | Cross-refs: ${relCR.replace(/\n/g, "; ")}`;
            parts.push(line);
          });
          parts.push(`</existing_relationships>`);
          }
        }
        break;
      }
    }

    // ─── SHARED: Literary craft context for ALL tabs ───
    if (project.thematicArgument?.thesis) {
      const ta = project.thematicArgument;
      let taLine = `Thematic argument: "${ta.thesis}"`;
      if (ta.antithesis) taLine += ` vs "${ta.antithesis}"`;
      if (ta.synthesis) taLine += ` → "${ta.synthesis}"`;
      parts.push(`\n${taLine}`);
    }
    if (project.motifs?.length > 0) {
      const named = (project.motifs || []).filter(m => m.name);
      if (named.length > 0) parts.push(`Motifs: ${named.map(m => `${m.name}${m.meaning ? ` (${m.meaning})` : ""}`).join(", ")}`);
    }
    if (project.readerKnowledge?.length > 0) {
      const facts = (project.readerKnowledge || []).filter(rk => rk.fact);
      if (facts.length > 0) parts.push(`Reader knows: ${facts.map(rk => `"${_truncateAtBoundary(rk.fact, 60)}"`).join("; ")}`);
    }
    // Current chapter craft settings
    const tabCurCh = project.chapters?.[chapterIdx];
    if (tabCurCh?.narrativeDistance) parts.push(`Narrative distance: ${tabCurCh.narrativeDistance}`);
    if (tabCurCh?.sensoryPalette) parts.push(`Sensory palette: ${tabCurCh.sensoryPalette}`);
    if (tabCurCh?.subtextNotes) parts.push(`Subtext: ${tabCurCh.subtextNotes}`);
    if (tabCurCh?.tensionLevel && tabCurCh.tensionLevel !== 5) parts.push(`Tension level: ${tabCurCh.tensionLevel}/10`);

    return parts.filter(s => s).join("\n");
  }
};

// ═══════════════════════════════════════════════════════════════════════
//   AGENT RUNTIME — Multi-agent orchestration for smarter memory retrieval
//   Architecture: Orchestrator → Specialist Agents (parallel) → Writing Agent → Post-processors
// ═══════════════════════════════════════════════════════════════════════

// Agent model economics
// Hard tasks use Grok 4.3. Easy/normal specialist work defaults to MiniMax M3.
// This keeps the big final context available while avoiding paid orchestration and giant specialist prompts for routine work.
const AGENT_HARD_MODEL = "x-ai/grok-4.3";
const AGENT_ECONOMY_MODEL = "minimax/minimax-m3";
const AGENT_DEFAULT_MODEL = AGENT_ECONOMY_MODEL;
const AGENT_DIFFICULTY_LABELS = { easy: "Easy", normal: "Normal", hard: "Hard" };

// Agent roles — parent/tier/budget drive the visible hierarchy and the default model.
const AGENT_ROLES = [
  { key: "orchestrator", parent: "control", tier: "normal", label: "Orchestrator", desc: "Routes hard requests and plans which specialists run", budget: 1800 },
  { key: "sceneStructureAgent", parent: "specialists", tier: "normal", label: "Scene Structure Agent", desc: "Scene goal, beat order, conflict, reversal, payoff", budget: 1800 },
  { key: "characterAgent", parent: "specialists", tier: "normal", label: "Character Continuity Agent", desc: "Emotional state, voice, obligations, knowledge", budget: 1800 },
  { key: "relationshipAgent", parent: "specialists", tier: "normal", label: "Relationship Dynamics Agent", desc: "Dynamic stage, tension, trust, subtext", budget: 1800 },
  { key: "timelineAgent", parent: "specialists", tier: "normal", label: "Timeline & Continuity Agent", desc: "Story dates, flashbacks, before/after state", budget: 1500 },
  { key: "loreRulesAgent", parent: "specialists", tier: "normal", label: "Lore & Rules Agent", desc: "World rules, laws, magic/tech constraints, active conditions", budget: 1800 },
  { key: "settingAgent", parent: "specialists", tier: "easy", label: "Setting & Atmosphere Agent", desc: "Place, sensory palette, mood, physical grounding", budget: 1400 },
  { key: "revealAgent", parent: "specialists", tier: "normal", label: "Reveal & Reader Knowledge Agent", desc: "Spoiler boundaries, dramatic irony, who knows what", budget: 1500 },
  { key: "thematicAgent", parent: "specialists", tier: "normal", label: "Thematic Argument Agent", desc: "Motifs, theme pressure, literary layer", budget: 1500 },
  { key: "craftAgent", parent: "specialists", tier: "easy", label: "Voice & Craft Agent", desc: "Narrative distance, style, register, sentence feel", budget: 1200 },
  { key: "standardsAgent", parent: "specialists", tier: "easy", label: "Craft Standards Agent", desc: "Genre fit, prose standards, avoid-list checks", budget: 1000 },
  { key: "assembler", parent: "assembly", tier: "normal", label: "Context Assembler", desc: "Merges specialist briefs into a compact handoff", budget: 1200 },
  { key: "writer", parent: "main", tier: "hard", label: "Writing Agent (Main)", desc: "Generates the final prose/content using compact briefs", budget: 48000 },
  { key: "jsonAgent", parent: "main", tier: "normal", label: "Structured Data Agent", desc: "Generates clean JSON for auto-fill and sync tasks", budget: 12000 },
  { key: "analysisAgent", parent: "main", tier: "hard", label: "Analysis Agent", desc: "Deep diagnostics, story audits, broad reasoning", budget: 24000 },
  { key: "continuityChecker", parent: "post", tier: "normal", label: "Continuity Checker (post)", desc: "Catches inconsistencies after generation", budget: 3000 },
  { key: "voiceDriftDetector", parent: "post", tier: "easy", label: "Voice Drift Detector (post)", desc: "Flags character voice inconsistency", budget: 2400 },
  { key: "hookScorer", parent: "post", tier: "easy", label: "Chapter-End Hook Scorer (post)", desc: "Rates chapter endings 0-10", budget: 1200 },
  { key: "motifAuditor", parent: "post", tier: "easy", label: "Motif Weaving Auditor (post)", desc: "Tracks motif usage across chapters", budget: 1800 },
  { key: "stateUpdater", parent: "post", tier: "normal", label: "State Updater (post)", desc: "Updates character living state + relationship evolution + reveal flags", budget: 4000 },
];

const getAgentRole = (role) => AGENT_ROLES.find(a => a.key === role) || null;
const getAgentDefaultModel = (role, taskDifficulty = null) => {
  const r = getAgentRole(role);
  const tier = taskDifficulty || r?.tier || "normal";
  return tier === "hard" ? AGENT_HARD_MODEL : AGENT_ECONOMY_MODEL;
};
const getAgentModel = (settings, role, taskDifficulty = null) => {
  const override = settings?.agentModels?.[role];
  return override || getAgentDefaultModel(role, taskDifficulty);
};
const getAgentBudget = (role, taskDifficulty = null) => {
  const r = getAgentRole(role);
  const base = r ? r.budget : 1600;
  // User request: all agents/subagents get 5x token budget, capped at 100k.
  // Do not down-clamp easy/normal tasks; the role budget is already the source of truth.
  return Math.min(base * AGENT_TOKEN_MULTIPLIER, AGENT_TOKEN_HARD_CAP);
};

const classifyAgentTaskDifficulty = (userRequest = "", taskHint = "") => {
  const text = `${userRequest} ${taskHint}`.toLowerCase();
  if (/\b(deep|full|entire|whole|audit|analy[sz]e|diagnos|complex|continuity|sync story|all chapters|generate chapter|long scene|rewrite chapter|worldbuild|orchestrat|multi-step|hard)\b/.test(text)) return "hard";
  if (/\b(quick|short|tiny|grammar|typo|tighten|polish|caption|rename|one line|summari[sz]e briefly|easy)\b/.test(text)) return "easy";
  return "normal";
};

const buildHeuristicAgentPlan = ({ userRequest = "", taskHint = "", difficulty = "normal" }) => {
  const text = `${userRequest} ${taskHint}`.toLowerCase();
  const specialists = new Set();
  const add = (...keys) => keys.forEach(k => specialists.add(k));

  if (difficulty === "easy") {
    if (/grammar|typo|tighten|polish|line edit|rewrite/.test(text)) add("craftAgent", "standardsAgent");
    else if (/relationship|chemistry|tension|trust/.test(text)) add("relationshipAgent", "craftAgent");
    else if (/character|voice|emotion|pov/.test(text)) add("characterAgent", "craftAgent");
    else add("craftAgent");
  } else {
    add("sceneStructureAgent", "characterAgent", "craftAgent", "standardsAgent");
    if (/dialogue|conversation|kiss|fight|argue|confess|tension|relationship|chemistry|trust|lover|enemy/.test(text)) add("relationshipAgent");
    if (/timeline|flashback|date|before|after|continuity|dead|alive|chapter/.test(text)) add("timelineAgent");
    if (/world|location|setting|place|room|city|law|rule|magic|technology|culture|religion/.test(text)) add("settingAgent", "loreRulesAgent");
    if (/secret|reveal|reader knows|dramatic irony|spoiler|knowledge/.test(text)) add("revealAgent");
    if (/theme|motif|symbol|literary|argument/.test(text)) add("thematicAgent");
  }

  const maxAgents = difficulty === "easy" ? 2 : 5;
  return {
    task_type: /json|structured|fill|sync/.test(text) ? "structured_data" : /analy[sz]e|audit|diagnos/.test(text) ? "analysis" : "creative_writing",
    difficulty,
    planner: "local-economy",
    required_specialists: [...specialists].filter(k => SPECIALIST_AGENTS[k]).slice(0, maxAgents),
    skip_specialists: [],
    reasoning: `Local economy planner selected ${Math.min(specialists.size, maxAgents)} focused specialist(s) to avoid an extra orchestrator call.`,
    output_mode: /json|structured/.test(text) ? "json" : "prose",
  };
};

// Low-level agent API call — uses OpenRouter
const _callAgent = async ({ role, system, user, settings, signal, temperature = 0.7, json = false, taskDifficulty = null }) => {
  const model = getAgentModel(settings, role, taskDifficulty);
  const budget = getAgentBudget(role, taskDifficulty);
  if (!settings?.apiKey) throw new Error("API key not set");

  const body = {
    model,
    messages: [
      { role: "system", content: system },
      { role: "user", content: user },
    ],
    temperature,
    max_tokens: Math.min(budget, AGENT_TOKEN_HARD_CAP),
  };
  if (json) body.response_format = { type: "json_object" };

  const res = await fetch("https://openrouter.ai/api/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${settings.apiKey}`,
      "HTTP-Referer": window.location.origin,
      "X-Title": "NovelForge",
    },
    body: JSON.stringify(body),
    signal,
  });
  if (!res.ok) {
    const errData = await res.json().catch(() => ({}));
    throw new Error(errData.error?.message || `Agent ${role} failed (${res.status})`);
  }
  const data = await res.json();
  return data.choices?.[0]?.message?.content || "";
};

// ═══ MEMORY INDEX — Lightweight structured summary of the project ═══
// Built once, cached, consulted by orchestrator. Avoids passing the whole project around.
const buildMemoryIndex = (project, currentChapterIdx) => {
  if (!project) return null;
  const currentCh = project.chapters?.[currentChapterIdx];
  const currentChNum = ContextEngine._chapterNum(project, currentChapterIdx);
  const currentDate = ContextEngine._currentStoryDate(project, currentChapterIdx);
  const flashback = ContextEngine._detectFlashback(project, currentChapterIdx);

  return {
    meta: {
      title: project.title || "Untitled",
      genre: project.genre || "",
      pov: project.pov || "",
      totalChapters: project.chapters?.length || 0,
      totalWords: (project.chapters || []).reduce((s, c) => s + wordCount(c.content || ""), 0),
    },
    current: {
      chapterIdx: currentChapterIdx,
      chapterNum: currentChNum,
      chapterTitle: currentCh?.title || "",
      chapterPov: currentCh?.pov || project.pov || "",
      sceneNotes: currentCh?.sceneNotes || "",
      narrativeDistance: currentCh?.narrativeDistance || "",
      sensoryPalette: currentCh?.sensoryPalette || "",
      subtextNotes: currentCh?.subtextNotes || "",
      tensionLevel: currentCh?.tensionLevel || 5,
      storyDate: currentDate ? String(currentDate) : "",
      isFlashback: !!flashback,
      wordsWritten: wordCount(currentCh?.content || ""),
    },
    charactersIndex: (project.characters || []).filter(c => c.name).map(c => ({
      id: c.id,
      name: c.name,
      role: c.role,
      isBulk: !!c.isBulk,
      status: c.status || "alive",
    })),
    plotIndex: (project.plotOutline || []).map(pl => ({
      id: pl.id, chapter: pl.chapter, title: pl.title,
      date: pl.date || "", sceneType: pl.sceneType || "",
    })),
    worldIndex: (project.worldBuilding || []).filter(w => w.name).map(w => ({
      id: w.id, name: w.name, category: w.category || "",
    })),
    relationshipCount: (project.relationships || []).length,
    motifsIndex: (project.motifs || []).filter(m => m.name).map(m => ({ id: m.id, name: m.name, meaning: m.meaning || "" })),
    hasThematicArgument: !!(project.thematicArgument?.thesis),
    readerKnowledgeCount: (project.readerKnowledge || []).length,
  };
};

// ═══ ORCHESTRATOR — Plans the run ═══
const runOrchestrator = async ({ userRequest, memoryIndex, taskHint, settings, signal, taskDifficulty = "hard", appConfig = null }) => {
  const defaultSystem = `You are the orchestrator for a multi-agent novel-writing assistant. Your job: analyze the user's request and decide which specialist agents to consult.

Return ONLY a JSON object with this shape:
{
  "task_type": "creative_writing" | "structured_data" | "analysis" | "question_answer" | "edit",
  "required_specialists": [array of specialist keys],
  "skip_specialists": [array of specialist keys],
  "reasoning": "brief explanation",
  "output_mode": "prose" | "json" | "mixed"
}

Available specialists: sceneStructureAgent, characterAgent, timelineAgent, settingAgent, loreRulesAgent, relationshipAgent, revealAgent, thematicAgent, craftAgent, standardsAgent.

GUIDELINES:
- Creative writing (continue, rewrite, dialogue, scene): include sceneStructureAgent, characterAgent, timelineAgent, settingAgent, loreRulesAgent, craftAgent, standardsAgent. Add relationshipAgent if multiple characters interact. Add revealAgent when secrets/backstory/reader knowledge matters. Add thematicAgent for literary or motif-heavy scenes.
- Structured data (generate character JSON, plot outline): include the relevant domain specialist, sceneStructureAgent when plot/chapters are involved, and standardsAgent.
- Analysis (why is X falling flat?): include all specialists.
- Quick edit (fix grammar, tighten): include ONLY craftAgent and standardsAgent unless continuity is explicitly involved.
- Question answering: include whichever specialists hold the answer.
- Do not over-delegate: prefer 3-6 specialists for ordinary work, 7-10 only for complex story decisions.
Skip specialists that aren't needed to save tokens.`;

  const defaultUser = `USER REQUEST: ${userRequest}
${taskHint ? `HINT: ${taskHint}` : ""}

MEMORY INDEX:
${JSON.stringify(memoryIndex, null, 2)}

Return your plan as JSON.`;
  const vars = { userRequest, taskHint: taskHint || "", memoryIndex: JSON.stringify(memoryIndex, null, 2) };
  const system = promptTextOrFallback(appConfig, "agents.orchestrator", "system", vars, defaultSystem);
  const user = promptTextOrFallback(appConfig, "agents.orchestrator", "user", vars, defaultUser);

  const raw = await _callAgent({ role: "orchestrator", system, user, settings, signal, temperature: 0.2, json: true, taskDifficulty });
  try {
    return JSON.parse(raw);
  } catch {
    // Fallback plan if orchestrator fails to return valid JSON
    return {
      task_type: "creative_writing",
      required_specialists: ["sceneStructureAgent", "characterAgent", "craftAgent", "standardsAgent"],
      skip_specialists: [],
      reasoning: "Orchestrator fallback — used default creative writing plan",
      output_mode: "prose",
    };
  }
};

// ═══ SPECIALIST AGENTS — each produces a compact brief ═══
const SPECIALIST_AGENTS = {
  characterAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      const curCh = project.chapters?.[chapterIdx];
      const pov = ContextEngine._effectivePov(project, chapterIdx);
      const povChar = (project.characters || []).find(c => c.name === pov);
      const chars = project.characters || [];
      return JSON.stringify({
        povCharacter: povChar ? {
          name: povChar.name, role: povChar.role, personality: povChar.personality,
          speechPattern: povChar.speechPattern, voiceSamples: povChar.voiceSamples,
          desires: povChar.desires, fears: povChar.fears, arc: povChar.arc,
          shortTermGoals: povChar.shortTermGoals, status: povChar.status,
          // AI-maintained living state (what they're feeling/owing/knowing right now)
          currentEmotionalState: povChar.currentEmotionalState || "",
          obligationsOwed: povChar.obligationsOwed || "",
          knowledgeState: povChar.knowledgeState || "",
          // Reveal flags (affect what AI knows to use)
          backstoryRevealed: !!povChar.backstoryRevealed,
          secretRevealed: !!povChar.secretRevealed,
          hasAppeared: !!povChar.hasAppeared,
          backstory: povChar.backstoryRevealed ? povChar.backstory : "[NOT YET REVEALED — hold back]",
          hiddenSecrets: povChar.secretRevealed ? povChar.hiddenSecrets : "[NOT YET REVEALED — hold back]",
        } : null,
        otherCharacters: chars.filter(c => c.name && c.id !== povChar?.id && !c.isBulk).slice(0, 10).map(c => ({
          name: c.name, role: c.role, status: c.status,
          briefPersonality: (c.personality || "").slice(0, 200),
          currentEmotionalState: c.currentEmotionalState || "",
          obligationsOwed: c.obligationsOwed || "",
          hasAppeared: !!c.hasAppeared,
        })),
        currentSceneNotes: curCh?.sceneNotes || "",
        currentChapterPov: pov,
      });
    },
    system: `You are the Character Continuity Agent. Return a COMPACT brief (150-300 words) about the POV character's state going into this scene: emotional state (use the currentEmotionalState field as baseline), voice register, recent obligations made (obligationsOwed), what they currently know (knowledgeState), unfulfilled promises, psychological momentum. Also briefly note any other characters present and their current states. If backstoryRevealed or secretRevealed is false, DO NOT surface that material — it hasn't been revealed yet. Be specific and actionable.`,
  },

  timelineAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      return JSON.stringify({
        currentChapter: memoryIndex.current,
        allPlotEntries: memoryIndex.plotIndex,
        isFlashback: memoryIndex.current.isFlashback,
        characterStatuses: memoryIndex.charactersIndex.map(c => ({
          name: c.name, status: c.status,
        })),
      });
    },
    system: `You are the Timeline & Continuity Agent. Return a COMPACT brief (100-200 words) about the timeline state: current story date/chapter, what has happened before this point, what hasn't happened yet, whether this is a flashback (if so, what the reader already knows that the characters don't). Be precise — the writing agent uses this to avoid continuity errors.`,
  },

  settingAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      const curCh = project.chapters?.[chapterIdx];
      const plotEntry = ContextEngine._plotEntryForChapter(project, chapterIdx);
      const locations = (project.worldBuilding || []).filter(w => w.category === "Location" || !w.category);
      // Focus on current scene's locations
      const sceneLocationIds = plotEntry?.locations || [];
      const sceneLocations = sceneLocationIds.length > 0
        ? locations.filter(l => sceneLocationIds.includes(l.id))
        : locations.slice(0, 5);
      return JSON.stringify({
        sceneLocations: sceneLocations.map(l => ({
          name: l.name, atmosphere: l.atmosphere, sensoryDetails: l.sensoryDetails,
          dangers: l.dangers, rules: l.rules, population: l.population,
        })),
        chapterSensoryPalette: curCh?.sensoryPalette || "",
        chapterMood: plotEntry?.sceneType || "",
      });
    },
    system: `You are the Setting & Atmosphere Agent. Return a COMPACT brief (100-200 words) about the scene's physical environment: where it takes place, atmosphere, dominant senses, tonal precedents from similar past scenes. The writing agent uses this to ground the prose in a specific place.`,
  },

  relationshipAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      const plotEntry = ContextEngine._plotEntryForChapter(project, chapterIdx);
      const sceneCharIds = plotEntry?.characters || [];
      const relevantRels = (project.relationships || []).filter(r =>
        sceneCharIds.includes(r.char1) || sceneCharIds.includes(r.char2) ||
        sceneCharIds.length === 0
      ).slice(0, 8);
      const charMap = {};
      (project.characters || []).forEach(c => { charMap[c.id] = c.name; });
      // For each relationship, show its most recent chapter evolution snapshot
      return JSON.stringify({
        currentChapterIdx: chapterIdx,
        relevantRelationships: relevantRels.map(r => {
          // Get the most recent chapter evolution entry <= current chapter
          const evo = r.chapterEvolution || {};
          const evoKeys = Object.keys(evo).map(k => parseInt(k, 10)).filter(n => !isNaN(n) && n <= chapterIdx).sort((a, b) => b - a);
          const latestEvo = evoKeys.length > 0 ? evo[evoKeys[0]] : null;
          return {
            char1: charMap[r.char1] || r.char1,
            char2: charMap[r.char2] || r.char2,
            // Foundational (static)
            category: r.category,
            conflictSource: r.conflictSource,
            terms: r.terms,
            taboos: r.taboos,
            evolutionTimeline: r.evolutionTimeline,
            // Current chapter state (AI-maintained, falls back to base fields)
            status: latestEvo?.status || r.status,
            tension: latestEvo?.tension || r.tension,
            tensionType: latestEvo?.tensionType || r.tensionType,
            dynamic: latestEvo?.dynamic || r.dynamic,
            trustLevel: latestEvo?.trustLevel || r.trustLevel,
            chemistry: latestEvo?.chemistry || r.chemistry,
            powerDynamic: latestEvo?.powerDynamic || r.powerDynamic,
            char1Perspective: latestEvo?.char1Perspective || r.char1Perspective,
            char2Perspective: latestEvo?.char2Perspective || r.char2Perspective,
            sharedSecrets: latestEvo?.sharedSecrets || r.sharedSecrets,
            progression: latestEvo?.progression || r.progression,
            evolutionChapter: evoKeys[0] ?? null,
          };
        }),
      });
    },
    system: `You are the Relationship Dynamics Agent. Return a COMPACT brief (100-200 words) about relationships between characters in this scene. Focus on their CURRENT state (which may differ from foundational setup if chapter evolution has occurred): current dynamic stage, tension level, trust, power shifts, unresolved subtext, what's unsaid. Reference evolutionChapter if shown (means fields are from that chapter's state). The writing agent uses this to make interactions feel earned.`,
  },

  sceneStructureAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      const curCh = project.chapters?.[chapterIdx];
      const plotEntry = ContextEngine._plotEntryForChapter(project, chapterIdx);
      const prev = chapterIdx > 0 ? project.chapters?.[chapterIdx - 1] : null;
      const next = project.chapters?.[chapterIdx + 1] || null;
      return JSON.stringify({
        currentChapter: memoryIndex.current,
        plotEntry: plotEntry ? {
          chapter: plotEntry.chapter, title: plotEntry.title, summary: plotEntry.summary,
          beats: plotEntry.beats || [], sceneType: plotEntry.sceneType || "",
          pov: plotEntry.pov || "", date: plotEntry.date || "",
          characters: plotEntry.characters || [], locations: plotEntry.locations || [],
        } : null,
        sceneNotes: curCh?.sceneNotes || "",
        previousChapterSummary: prev?.summary || "",
        nextChapterTitle: next?.title || "",
        writtenWords: wordCount(curCh?.content || ""),
      });
    },
    system: `You are the Scene Structure Agent. Return a COMPACT brief (100-200 words) focused only on what the scene must DO: scene goal, entry point, beat order, stakes, escalation, turn, and payoff. Do not write prose. Give the writing agent a clear path through the moment.`,
  },

  loreRulesAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      const plotEntry = ContextEngine._plotEntryForChapter(project, chapterIdx);
      const locIds = plotEntry?.locations || [];
      const relevantWorld = (project.worldBuilding || []).filter(w =>
        locIds.includes(w.id) || ["Rule / Law", "Magic System", "Technology", "Culture", "Religion", "Organization"].includes(w.category)
      ).slice(0, 14);
      const activeConditions = (project.worldStateLedger || []).filter(e => (e.fromChapter ?? 0) <= (memoryIndex.current.chapterNum || chapterIdx + 1));
      return JSON.stringify({
        activeConditions,
        relevantWorld: relevantWorld.map(w => ({
          id: w.id, name: w.name, category: w.category,
          description: w.description, rules: w.rules, enforcement: w.enforcement,
          magicRules: w.magicRules, magicCost: w.magicCost,
          techLimitations: w.techLimitations, culturalNorms: w.culturalNorms,
          orgPurpose: w.orgPurpose, dangers: w.dangers,
        })),
      });
    },
    system: `You are the Lore & Rules Agent. Return a COMPACT brief (100-200 words) listing only the world constraints that should affect this output: laws, magic/tech limits, active conditions, organization pressure, cultural norms, location dangers. Be practical. Do not worldbuild new facts unless the user asks.`,
  },

  revealAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      const curChNum = memoryIndex.current.chapterNum || chapterIdx + 1;
      return JSON.stringify({
        currentChapter: curChNum,
        readerKnowledge: (project.readerKnowledge || []).filter(rk => rk.fact).map(rk => ({
          fact: rk.fact, revealedInChapter: rk.revealedInChapter || null, knownBy: rk.knownBy || [],
        })),
        characterRevealFlags: (project.characters || []).filter(c => c.name && !c.isBulk).map(c => ({
          id: c.id, name: c.name,
          backstoryRevealed: !!c.backstoryRevealed,
          secretRevealed: !!c.secretRevealed,
          hasBackstory: !!c.backstory,
          hasHiddenSecrets: !!c.hiddenSecrets,
          status: c.status || "alive",
        })),
        motifs: (project.motifs || []).filter(m => m.name).map(m => ({ name: m.name, meaning: m.meaning || "", evolution: m.evolution || "" })),
      });
    },
    system: `You are the Reveal & Reader Knowledge Agent. Return a COMPACT brief (80-160 words) about spoiler boundaries and dramatic irony: what the reader knows, what characters know, what must stay hidden, and which motifs/reveals may be used now. Be strict about unrevealed secrets.`,
  },

  thematicAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      return JSON.stringify({
        thematicArgument: project.thematicArgument || null,
        motifs: project.motifs || [],
        readerKnowledge: (project.readerKnowledge || []).filter(rk => rk.fact),
        currentChapter: memoryIndex.current.chapterNum,
      });
    },
    system: `You are the Thematic Argument Agent. Return a COMPACT brief (100-200 words) about the thematic layer: what argument the story is making, which motifs are available to weave in naturally, what the reader knows that characters don't (dramatic irony opportunities). The writing agent uses this to add literary depth.`,
  },

  craftAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      const curCh = project.chapters?.[chapterIdx];
      return JSON.stringify({
        narrativeDistance: curCh?.narrativeDistance || "",
        sensoryPalette: curCh?.sensoryPalette || "",
        subtextNotes: curCh?.subtextNotes || "",
        tensionLevel: curCh?.tensionLevel || 5,
        pov: curCh?.pov || project.pov || "",
      });
    },
    system: `You are the Voice & Craft Agent. Return a SHORT brief (50-100 words) specifying exactly HOW the next prose should be written: narrative distance (cinematic/close-third/deep-interiority), sensory focus, subtext layer to maintain, tension level, POV. Be directive.`,
  },

  standardsAgent: {
    buildContext: (project, chapterIdx, memoryIndex) => {
      return JSON.stringify({
        genre: project.genre || "",
        writingStyle: project.writingStyle || "",
        avoidList: project.avoidList || "",
        heatLevel: project.heatLevel || 3,
      });
    },
    system: `You are the Craft Standards Agent. Return a SHORT brief (50-100 words) specifying prose quality standards for this genre: what to lean into, what to avoid (purple prose, clichés, banned phrases), voice precedents. Be concise and actionable.`,
  },
};

// Run a specialist — returns a compact brief string
const SPECIALIST_PROMPT_IDS = {
  sceneStructureAgent: "agent.sceneStructure",
  characterAgent: "agent.character",
  relationshipAgent: "agent.relationship",
  timelineAgent: "agent.continuity",
  loreRulesAgent: "agent.loreRules",
  settingAgent: "agent.setting",
  revealAgent: "agent.revealReaderKnowledge",
  thematicAgent: "agent.thematic",
  craftAgent: "agent.style",
  standardsAgent: "agent.standards",
};
const runSpecialist = async ({ key, project, chapterIdx, memoryIndex, settings, signal, taskDifficulty = null, appConfig = null }) => {
  const spec = SPECIALIST_AGENTS[key];
  if (!spec) throw new Error(`Unknown specialist: ${key}`);
  const context = spec.buildContext(project, chapterIdx, memoryIndex);
  const promptId = SPECIALIST_PROMPT_IDS[key] || `agent.${key}`;
  const vars = { context, project: JSON.stringify(project || {}, null, 2), memoryIndex: JSON.stringify(memoryIndex || {}, null, 2), chapterIdx, chapterNumber: chapterIdx + 1 };
  const system = promptTextOrFallback(appConfig, promptId, "system", vars, spec.system);
  const user = promptTextOrFallback(appConfig, promptId, "user", vars, context);
  return _callAgent({
    role: key, system, user, settings, signal, temperature: 0.4, taskDifficulty,
  });
};

// ═══ THE MAIN AGENT RUNTIME ═══
const AgentRuntime = {
  _briefCache: new Map(),
  // Cheap, order-independent string hash for fingerprinting content.
  _hash(str) {
    let h = 5381;
    for (let i = 0; i < str.length; i++) h = ((h << 5) + h + str.charCodeAt(i)) | 0;
    return (h >>> 0).toString(36);
  },
  _cacheKeyFor(key, project, chapterIdx) {
    const curCh = project.chapters?.[chapterIdx];
    // Content fingerprint — busts the cache when ANY relevant entity is edited in place,
    // not just when counts change. Previously edits that kept counts the same returned stale briefs.
    const charFp = this._hash(JSON.stringify((project.characters || []).map(c =>
      [c.id, c.name, c.role, c.personality, c.speechPattern, c.voiceSamples, c.desires, c.fears,
       c.arc, c.status, c.currentEmotionalState, c.knowledgeState, c.obligationsOwed,
       c.backstoryRevealed, c.secretRevealed, c.hasAppeared])));
    const worldFp = this._hash(JSON.stringify((project.worldBuilding || []).map(w =>
      [w.id, w.name, w.category, w.description, w.atmosphere, w.frequentCharacters])));
    const relFp = this._hash(JSON.stringify((project.relationships || []).map(r =>
      [r.id, r.char1, r.char2, r.dynamic, r.status, r.tension, r.tensionType, r.trustLevel,
       r.progression, r.chapterEvolution])));
    const plotFp = this._hash(JSON.stringify((project.plotOutline || []).map(p =>
      [p.chapter, p.title, p.summary, p.sceneType, p.pov, p.date, p.characters, p.locations])));
    const sig = [
      key, chapterIdx,
      (curCh?.content || "").length,
      curCh?.sceneNotes || "",
      curCh?.narrativeDistance || "",
      curCh?.sensoryPalette || "",
      curCh?.subtextNotes || "",
      curCh?.tensionLevel || 5,
      curCh?.pov || "",
      charFp, worldFp, relFp, plotFp,
    ].join("|");
    return sig;
  },

  async runFull({ userRequest, project, chapterIdx, taskHint, settings, signal, onProgress, appConfig = null }) {
    if (!settings?.apiKey) throw new Error("API key not set");
    if (!settings?.agentsEnabled) throw new Error("Multi-agent mode disabled");

    const memoryIndex = buildMemoryIndex(project, chapterIdx);
    const difficulty = classifyAgentTaskDifficulty(userRequest, taskHint);
    const useEconomyPlanner = settings?.agentEconomyMode !== false && settings?.agentPlannerMode !== "always-llm" && difficulty !== "hard";
    onProgress?.({ stage: "memory", message: "Scanning project memory, current chapter, cast, plot, world, and relationships." });
    onProgress?.({ stage: "economy", message: `Task classified as ${AGENT_DIFFICULTY_LABELS[difficulty] || difficulty}. ${useEconomyPlanner ? "Using local economy planner to avoid an extra orchestrator call." : "Using Grok 4.3 orchestrator for hard planning."}`, difficulty });

    // 1. Plan the run. Easy/normal tasks use local routing to save money; hard tasks use the LLM orchestrator.
    const plan = useEconomyPlanner
      ? buildHeuristicAgentPlan({ userRequest, taskHint, difficulty })
      : await runOrchestrator({ userRequest, memoryIndex, taskHint, settings, signal, taskDifficulty: difficulty, appConfig });
    plan.difficulty = plan.difficulty || difficulty;
    onProgress?.({ stage: "plan", plan, message: plan.reasoning || "Routing plan ready." });

    // 2. Run specialists in parallel (filtered by plan). Keep the specialist set small on easy/normal tasks.
    const specialistKeys = plan.required_specialists || [];
    const maxSpecialists = difficulty === "hard" ? 8 : difficulty === "normal" ? 5 : 2;
    const specialistsToRun = specialistKeys.filter(k => SPECIALIST_AGENTS[k]).slice(0, maxSpecialists);
    onProgress?.({ stage: "delegation", message: `Delegating to ${specialistsToRun.length} focused specialist${specialistsToRun.length === 1 ? "" : "s"} on ${difficulty} mode.`, specialists: specialistsToRun });

    const briefs = await Promise.all(
      specialistsToRun.map(async (key) => {
        const cacheKey = this._cacheKeyFor(key, project, chapterIdx);
        const label = AGENT_ROLES.find(r => r.key === key)?.label || key;
        if (this._briefCache.has(cacheKey)) {
          onProgress?.({ stage: "agent_cached", key, label, cached: true, message: `${label} reused a fresh cached brief.` });
          return { key, brief: this._briefCache.get(cacheKey), cached: true };
        }
        onProgress?.({ stage: "agent_start", key, label, message: `${label} is reading its focused slice of the story.` });
        try {
          const brief = await runSpecialist({ key, project, chapterIdx, memoryIndex, settings, signal, taskDifficulty: difficulty, appConfig });
          this._briefCache.set(cacheKey, brief);
          onProgress?.({ stage: "agent_done", key, label, message: `${label} returned a focused brief.`, preview: String(brief || "").slice(0, 220) });
          return { key, brief, cached: false };
        } catch (e) {
          onProgress?.({ stage: "agent_error", key, label, message: `${label} failed: ${e.message}` });
          return { key, brief: `[${key} failed: ${e.message}]`, cached: false, error: true };
        }
      })
    );
    onProgress?.({ stage: "briefs", briefs, message: `Collected ${briefs.length} specialist brief${briefs.length === 1 ? "" : "s"}.` });

    // 3. Assemble final prompt
    onProgress?.({ stage: "assembly", message: "Context Assembler is merging the briefs into the final writer prompt." });
    const assembledContext = briefs.map(b => {
      const label = AGENT_ROLES.find(r => r.key === b.key)?.label || b.key;
      return `<${b.key} label="${label}">
${b.brief}
</${b.key}>`;
    }).join("\n\n");
    onProgress?.({ stage: "ready", message: "Agent context is ready. Passing it to the writing model." });

    return {
      plan,
      briefs,
      assembledContext,
      memoryIndex,
      difficulty,
      economy: {
        planner: plan.planner || (useEconomyPlanner ? "local-economy" : "llm-orchestrator"),
        hardModel: AGENT_HARD_MODEL,
        economyModel: AGENT_ECONOMY_MODEL,
        specialistCount: specialistsToRun.length,
        note: "Specialists receive compact slices and return short briefs, reducing prompt mass sent into the final writer."
      },
    };
  },

  // Run a post-processor agent (continuity check, voice drift, hook scorer)
  async runPostProcessor({ key, project, chapterIdx, generatedContent, settings, signal, appConfig = null }) {
    const prompts = {
      continuityChecker: {
        system: `You are the Continuity Checker. Scan the generated content for any inconsistencies with the character profiles, world lore, relationships, or timeline. Return a JSON object: { "issues": [{ "type": "...", "description": "...", "suggestion": "..." }], "overallScore": 0-10 }`,
        user: `GENERATED CONTENT:\n${generatedContent}\n\nPROJECT CONTEXT:\n${JSON.stringify(buildMemoryIndex(project, chapterIdx), null, 2)}`,
      },
      voiceDriftDetector: {
        system: `You are the Voice Drift Detector. Compare dialogue in the generated content against each character's speechPattern and voiceSamples. Return JSON: { "driftScores": { "charName": 0-10 }, "issues": [{ "char": "...", "line": "...", "issue": "..." }] }`,
        user: `GENERATED CONTENT:\n${generatedContent}\n\nCHARACTERS:\n${JSON.stringify((project.characters || []).filter(c => c.name && !c.isBulk).map(c => ({ name: c.name, speechPattern: c.speechPattern, voiceSamples: c.voiceSamples })), null, 2)}`,
      },
      hookScorer: {
        system: `You are the Chapter-End Hook Scorer. Rate the last 2-3 paragraphs of the generated content for page-turner quality. Return JSON: { "score": 0-10, "technique": "question|urgency|reveal|shift|action", "notes": "brief suggestion" }`,
        user: `GENERATED CONTENT:\n${generatedContent}`,
      },
      motifAuditor: {
        system: `You are the Motif Weaving Auditor. Check how well the generated content integrates the project's motifs. Return JSON: { "motifsUsed": [array of motif names], "motifsNeglected": [array], "suggestions": "brief advice" }`,
        user: `GENERATED CONTENT:\n${generatedContent}\n\nPROJECT MOTIFS:\n${JSON.stringify(project.motifs || [], null, 2)}`,
      },
      stateUpdater: {
        system: `You are the State Updater. Read the chapter content and update each character's living state (currentEmotionalState, obligationsOwed, knowledgeState), reveal flags (backstoryRevealed, secretRevealed, hasAppeared), and every relationship state that changed because of the written scene. Relationships are AI-maintained from the manuscript, so create a relationship update whenever two named characters meaningfully interact, even if that pair is not already in the relationship list.
Return STRICTLY valid JSON:
{
  "characterUpdates": [
    { "id": "<character id from the list>", "name": "Elena", "currentEmotionalState": "...", "obligationsOwed": "...", "knowledgeState": "...", "backstoryRevealed": false, "secretRevealed": false, "hasAppeared": true, "status": "alive" }
  ],
  "relationshipUpdates": [
    { "char1": "<character id>", "char2": "<character id>", "category": "romantic|family|friendship|professional|mentor|rivalry|political|spiritual|other", "status": "strangers|acquaintances|developing|friends|friends-with-benefits|tension|dating|lovers|committed|complicated|estranged|enemies|enemies-to-lovers|exes|forbidden|unrequited", "tension": "none|low|medium|high|explosive", "tensionType": "romantic|hostile|suspenseful|competitive|protective|friendly|neutral|acquaintance|mixed", "dynamic": "...", "trustLevel": "none|low|medium|high|absolute", "chemistry": "...", "conflictSource": "...", "powerDynamic": "equal|char1-dominant|char2-dominant|shifting", "char1Perspective": "...", "char2Perspective": "...", "sharedSecrets": "...", "progression": "...", "keyScenes": "ChX: concrete evidence from this chapter" }
  ],
  "chapterState": { "chapterMomentum": 0-10, "emotionalAftertaste": "...", "chapterEndHookScore": 0-10 }
}
Always include character IDs for char1/char2 (copy them exactly from the lists below). Only include relationship fields supported by clear evidence in the scene. Do not invent off-page romance or conflict. Be precise and concise.`,
        user: `CHAPTER CONTENT:
${generatedContent}

CHARACTERS (use these exact ids):
${JSON.stringify((project.characters || []).filter(c => c.name && !c.isBulk).map(c => ({ id: c.id, name: c.name, role: c.role })), null, 2)}

EXISTING RELATIONSHIPS (char1/char2 are ids):
${JSON.stringify((project.relationships || []).map(r => ({ char1: r.char1, char2: r.char2, status: r.status, tension: r.tension, dynamic: r.dynamic })), null, 2)}`,
      },    };
    const p = prompts[key];
    if (!p) throw new Error(`Unknown post-processor: ${key}`);
    const vars = {
      output: generatedContent,
      generatedContent,
      context: JSON.stringify(buildMemoryIndex(project, chapterIdx), null, 2),
      project: JSON.stringify(project || {}, null, 2),
      characters: JSON.stringify((project.characters || []).filter(c => c.name && !c.isBulk).map(c => ({ id: c.id, name: c.name, role: c.role, speechPattern: c.speechPattern, voiceSamples: c.voiceSamples })), null, 2),
      relationships: JSON.stringify((project.relationships || []).map(r => ({ char1: r.char1, char2: r.char2, status: r.status, tension: r.tension, dynamic: r.dynamic })), null, 2),
      motifs: JSON.stringify(project.motifs || [], null, 2),
    };
    const promptId = `postprocess.${key}`;
    const system = promptTextOrFallback(appConfig, promptId, "system", vars, p.system);
    const user = promptTextOrFallback(appConfig, promptId, "user", vars, p.user);
    const raw = await _callAgent({ role: key, system, user, settings, signal, temperature: 0.3, json: true });
    try { return JSON.parse(raw); } catch { return { raw }; }
  },

  // Apply state updates from stateUpdater to the project
  applyStateUpdates(project, chapterIdx, updates) {
    if (!project || !updates) return project;
    const next = { ...project };
    const allChars = project.characters || [];
    // Resolve an AI-provided name/id reference to a single character, SAFELY.
    // Order: exact id → exact full name → exact alias → UNAMBIGUOUS first name. Ambiguous → null
    // (so we never write state onto the wrong same-named character).
    const resolveChar = (ref) => {
      if (!ref) return null;
      const r = String(ref).trim();
      const rl = r.toLowerCase();
      const byId = allChars.find(c => c.id === r);
      if (byId) return byId;
      const byFull = allChars.filter(c => c.name && c.name.toLowerCase() === rl);
      if (byFull.length === 1) return byFull[0];
      if (byFull.length > 1) return null; // ambiguous full-name → bail
      const byAlias = allChars.filter(c => {
        if (!c.aliases) return false;
        const list = (Array.isArray(c.aliases) ? c.aliases : String(c.aliases).split(",")).map(a => String(a).trim().toLowerCase());
        return list.includes(rl);
      });
      if (byAlias.length === 1) return byAlias[0];
      const byFirst = allChars.filter(c => c.name && c.name.trim().split(/\s+/)[0].toLowerCase() === rl);
      if (byFirst.length === 1) return byFirst[0];
      return null; // ambiguous or unknown
    };
    // Update characters
    if (Array.isArray(updates.characterUpdates)) {
      const newChars = [...allChars];
      updates.characterUpdates.forEach(upd => {
        const target = resolveChar(upd.id || upd.name);
        if (!target) return;
        const idx = newChars.findIndex(c => c.id === target.id);
        if (idx < 0) return;
        const keys = ["currentEmotionalState", "obligationsOwed", "knowledgeState", "backstoryRevealed", "secretRevealed", "hasAppeared", "status"];
        const patch = { lastUpdatedChapter: chapterIdx };
        keys.forEach(k => { if (upd[k] !== undefined) patch[k] = upd[k]; });
        newChars[idx] = { ...newChars[idx], ...patch };
      });
      next.characters = newChars;
    }
    // Update relationships — mirror the latest AI-maintained state at the top level and keep per-chapter history.
    // If the written chapter creates a meaningful new pair, create the relationship automatically.
    if (Array.isArray(updates.relationshipUpdates)) {
      const newRels = [...(project.relationships || [])];
      updates.relationshipUpdates.forEach(upd => {
        const c1 = resolveChar(upd.char1);
        const c2 = resolveChar(upd.char2);
        if (!c1 || !c2 || c1.id === c2.id) return;
        let idx = newRels.findIndex(r =>
          (r.char1 === c1.id && r.char2 === c2.id) || (r.char1 === c2.id && r.char2 === c1.id)
        );
        const evoKeys = ["category", "status", "tension", "tensionType", "dynamic", "trustLevel", "chemistry", "conflictSource", "powerDynamic", "char1Perspective", "char2Perspective", "sharedSecrets", "progression", "keyScenes", "terms", "taboos", "notes"];
        const evoPatch = {};
        evoKeys.forEach(k => { if (upd[k] !== undefined && upd[k] !== null) evoPatch[k] = normalizeAiValue(upd[k]); });
        if (Object.keys(evoPatch).length === 0) return;
        if (idx < 0) {
          newRels.push({
            id: uid(),
            char1: c1.id,
            char2: c2.id,
            category: evoPatch.category || defaultRelationshipCategory(project.genre),
            status: evoPatch.status || "developing",
            tension: evoPatch.tension || "medium",
            tensionType: evoPatch.tensionType || defaultTensionType(project.genre),
            dynamic: evoPatch.dynamic || `Emerging relationship between ${c1.name} and ${c2.name}.`,
            trustLevel: evoPatch.trustLevel || "medium",
            powerDynamic: evoPatch.powerDynamic || "equal",
            isPublic: true,
            aiMaintained: true,
            createdByAI: true,
            lastAISyncedAt: new Date().toISOString(),
            lastUpdatedChapter: chapterIdx,
            chapterEvolution: { [chapterIdx]: evoPatch },
            ...evoPatch,
          });
          return;
        }
        const existing = newRels[idx].chapterEvolution || {};
        newRels[idx] = {
          ...newRels[idx],
          ...evoPatch,
          aiMaintained: true,
          lastAISyncedAt: new Date().toISOString(),
          lastUpdatedChapter: chapterIdx,
          chapterEvolution: { ...existing, [chapterIdx]: evoPatch },
        };
      });
      next.relationships = newRels;
    }
    // Update chapter state
    if (updates.chapterState && next.chapters?.[chapterIdx]) {
      const ch = { ...next.chapters[chapterIdx] };
      if (updates.chapterState.chapterMomentum !== undefined) ch.chapterMomentum = updates.chapterState.chapterMomentum;
      if (updates.chapterState.emotionalAftertaste !== undefined) ch.emotionalAftertaste = updates.chapterState.emotionalAftertaste;
      if (updates.chapterState.chapterEndHookScore !== undefined) ch.chapterEndHookScore = updates.chapterState.chapterEndHookScore;
      const newChapters = [...next.chapters];
      newChapters[chapterIdx] = ch;
      next.chapters = newChapters;
    }
    return next;
  },

  clearCache() { this._briefCache.clear(); },
};

